const styles = "@import url('https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@400;600;700;900&family=Barlow:wght@300;400;500;600&display=swap');\n\n:root {\n  --bg: #080808;\n  --surface: #111;\n  --surface2: #181818;\n  --surface3: #1f1f1f;\n  --border: #252525;\n  --border2: #333;\n  --accent: #e8ff00;\n  --accent2: #ff3c00;\n  --blue: #4d9fff;\n  --green: #00e87a;\n  --text: #f0f0f0;\n  --muted: #555;\n  --muted2: #888;\n}\n\n* { box-sizing: border-box; margin: 0; padding: 0; }\n\nbody {\n  background: var(--bg);\n  color: var(--text);\n  font-family: 'Barlow', sans-serif;\n  font-weight: 300;\n  min-height: 100vh;\n  overflow-x: hidden;\n}\n\nbody::after {\n  content: '';\n  position: fixed;\n  inset: 0;\n  background: radial-gradient(ellipse at 0% 0%, rgba(232,255,0,0.03) 0%, transparent 60%);\n  pointer-events: none;\n  z-index: 0;\n}\n\n/* NAV */\n.nav {\n  display: flex;\n  align-items: center;\n  gap: 0;\n  border-bottom: 1px solid var(--border);\n  padding: 0 32px;\n  position: sticky;\n  top: 0;\n  background: rgba(8,8,8,0.95);\n  backdrop-filter: blur(12px);\n  z-index: 100;\n}\n\n.nav-brand {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 16px;\n  font-weight: 900;\n  letter-spacing: 0.05em;\n  text-transform: uppercase;\n  color: var(--accent);\n  padding: 16px 24px 16px 0;\n  border-right: 1px solid var(--border);\n  margin-right: 8px;\n  white-space: nowrap;\n}\n\n.nav-tab {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 12px;\n  font-weight: 600;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  padding: 18px 20px;\n  cursor: pointer;\n  color: var(--muted);\n  border-bottom: 2px solid transparent;\n  transition: all 0.15s;\n  white-space: nowrap;\n}\n\n.nav-tab:hover { color: var(--text); }\n.nav-tab.active { color: var(--accent); border-bottom-color: var(--accent); }\n\n.nav-status {\n  margin-left: auto;\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 11px;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  color: var(--muted);\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.status-dot {\n  width: 6px; height: 6px;\n  border-radius: 50%;\n  background: var(--muted);\n}\n\n.status-dot.ready { background: var(--green); box-shadow: 0 0 6px var(--green); }\n\n/* PAGES */\n.page { display: none; padding: 40px 32px; max-width: 1100px; margin: 0 auto; position: relative; z-index: 1; }\n.page.active { display: block; }\n\n/* HEADINGS */\n.page-title {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 11px;\n  font-weight: 700;\n  letter-spacing: 0.2em;\n  text-transform: uppercase;\n  color: var(--accent);\n  margin-bottom: 6px;\n}\n\n.page-heading {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: clamp(32px, 5vw, 52px);\n  font-weight: 900;\n  text-transform: uppercase;\n  line-height: 0.95;\n  letter-spacing: -0.01em;\n  margin-bottom: 8px;\n}\n\n.page-sub {\n  color: var(--muted2);\n  font-size: 14px;\n  line-height: 1.6;\n  max-width: 580px;\n  margin-bottom: 36px;\n}\n\n/* CARDS */\n.card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 2px;\n  padding: 24px;\n  position: relative;\n  overflow: hidden;\n}\n\n.card::before {\n  content: '';\n  position: absolute;\n  top: 0; left: 0; right: 0;\n  height: 1px;\n  background: linear-gradient(90deg, var(--accent) 0%, transparent 60%);\n  opacity: 0;\n  transition: opacity 0.2s;\n}\n\n.card:hover::before { opacity: 1; }\n\n.card-label {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 10px;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n  text-transform: uppercase;\n  color: var(--muted);\n  margin-bottom: 8px;\n}\n\n/* UPLOAD ZONE */\n.upload-zone {\n  border: 1px dashed var(--border2);\n  border-radius: 2px;\n  padding: 48px 32px;\n  text-align: center;\n  cursor: pointer;\n  transition: all 0.2s;\n  position: relative;\n}\n\n.upload-zone:hover, .upload-zone.drag { border-color: var(--accent); background: rgba(232,255,0,0.02); }\n.upload-zone input { position: absolute; inset: 0; opacity: 0; cursor: pointer; }\n\n.upload-icon {\n  font-size: 32px;\n  margin-bottom: 12px;\n  opacity: 0.4;\n}\n\n.upload-title {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 18px;\n  font-weight: 700;\n  text-transform: uppercase;\n  letter-spacing: 0.05em;\n  margin-bottom: 6px;\n}\n\n.upload-hint { font-size: 13px; color: var(--muted2); line-height: 1.5; }\n\n/* BUTTONS */\n.btn {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 14px;\n  font-weight: 700;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  padding: 12px 24px;\n  border: none;\n  border-radius: 2px;\n  cursor: pointer;\n  transition: all 0.15s;\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.btn-primary { background: var(--accent); color: #000; }\n.btn-primary:hover { background: #fff; }\n.btn-primary:disabled { opacity: 0.4; cursor: not-allowed; }\n\n.btn-secondary { background: transparent; border: 1px solid var(--border2); color: var(--muted2); }\n.btn-secondary:hover { border-color: var(--accent); color: var(--accent); }\n\n.btn-lg { font-size: 17px; padding: 16px 32px; width: 100%; justify-content: center; }\n\n/* PROGRESS */\n.progress-wrap { margin: 24px 0; }\n.progress-label { font-size: 12px; color: var(--muted2); margin-bottom: 8px; display: flex; justify-content: space-between; }\n.progress-bar { height: 2px; background: var(--border2); border-radius: 1px; overflow: hidden; }\n.progress-fill { height: 100%; background: var(--accent); border-radius: 1px; transition: width 0.4s ease; }\n\n/* STATS GRID */\n.stats-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));\n  gap: 12px;\n  margin-bottom: 32px;\n}\n\n.stat-card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 2px;\n  padding: 16px 20px;\n}\n\n.stat-value {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 32px;\n  font-weight: 900;\n  line-height: 1;\n  margin-bottom: 4px;\n}\n\n.stat-label { font-size: 11px; color: var(--muted2); text-transform: uppercase; letter-spacing: 0.1em; }\n\n/* VIDEO TABLE */\n.video-table { width: 100%; border-collapse: collapse; }\n.video-table th {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 10px;\n  font-weight: 700;\n  letter-spacing: 0.15em;\n  text-transform: uppercase;\n  color: var(--muted);\n  padding: 10px 12px;\n  text-align: left;\n  border-bottom: 1px solid var(--border);\n}\n\n.video-table td {\n  padding: 10px 12px;\n  border-bottom: 1px solid var(--border);\n  font-size: 13px;\n  vertical-align: middle;\n}\n\n.video-table tr:hover td { background: var(--surface2); }\n\n.perf-bar {\n  display: inline-block;\n  height: 4px;\n  border-radius: 2px;\n  background: var(--accent);\n  opacity: 0.6;\n  vertical-align: middle;\n  margin-left: 6px;\n}\n\n.badge-short { background: rgba(77,159,255,0.12); color: var(--blue); border: 1px solid rgba(77,159,255,0.2); font-family: 'Barlow Condensed', sans-serif; font-size: 9px; font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase; padding: 2px 6px; border-radius: 2px; }\n.badge-long { background: rgba(232,255,0,0.08); color: var(--accent); border: 1px solid rgba(232,255,0,0.15); font-family: 'Barlow Condensed', sans-serif; font-size: 9px; font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase; padding: 2px 6px; border-radius: 2px; }\n\n/* INSIGHT BLOCKS */\n.insights-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 32px; }\n@media (max-width: 700px) { .insights-grid { grid-template-columns: 1fr; } }\n\n.insight-card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 2px;\n  padding: 20px;\n}\n\n.insight-title {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 12px;\n  font-weight: 700;\n  letter-spacing: 0.15em;\n  text-transform: uppercase;\n  color: var(--accent);\n  margin-bottom: 12px;\n}\n\n.insight-item {\n  display: flex;\n  align-items: flex-start;\n  gap: 10px;\n  padding: 8px 0;\n  border-bottom: 1px solid var(--border);\n  font-size: 13px;\n  line-height: 1.5;\n  color: #ccc;\n}\n\n.insight-item:last-child { border-bottom: none; }\n.insight-dot { width: 5px; height: 5px; border-radius: 50%; background: var(--accent); margin-top: 5px; flex-shrink: 0; }\n.insight-dot.red { background: var(--accent2); }\n.insight-dot.blue { background: var(--blue); }\n\n/* GENERATE PAGE */\n.gen-layout { display: grid; grid-template-columns: 1fr 340px; gap: 24px; }\n@media (max-width: 800px) { .gen-layout { grid-template-columns: 1fr; } }\n\n.dna-panel {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 2px;\n  padding: 20px;\n  height: fit-content;\n  position: sticky;\n  top: 80px;\n}\n\n.dna-title {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 10px;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n  text-transform: uppercase;\n  color: var(--green);\n  margin-bottom: 12px;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.dna-dot { width: 6px; height: 6px; border-radius: 50%; background: var(--green); box-shadow: 0 0 6px var(--green); }\n\n.dna-content { font-size: 12px; line-height: 1.7; color: var(--muted2); max-height: 400px; overflow-y: auto; }\n\ntextarea {\n  width: 100%;\n  background: var(--surface2);\n  border: 1px solid var(--border);\n  border-radius: 2px;\n  color: var(--text);\n  font-family: 'Barlow', sans-serif;\n  font-size: 14px;\n  font-weight: 300;\n  line-height: 1.7;\n  padding: 16px;\n  resize: vertical;\n  min-height: 180px;\n  outline: none;\n  transition: border-color 0.2s;\n}\n\ntextarea:focus { border-color: var(--accent); }\ntextarea::placeholder { color: #2a2a2a; }\n\n/* CONCEPTS */\n.concept-card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 2px;\n  margin-bottom: 12px;\n  overflow: hidden;\n  animation: fadeUp 0.35s ease both;\n}\n\n@keyframes fadeUp {\n  from { opacity: 0; transform: translateY(16px); }\n  to { opacity: 1; transform: translateY(0); }\n}\n\n.concept-card:nth-child(1) { animation-delay: 0.05s; }\n.concept-card:nth-child(2) { animation-delay: 0.12s; }\n.concept-card:nth-child(3) { animation-delay: 0.19s; }\n.concept-card:nth-child(4) { animation-delay: 0.26s; }\n\n.concept-header {\n  display: grid;\n  grid-template-columns: 44px 1fr auto;\n  gap: 14px;\n  align-items: start;\n  padding: 18px 20px;\n  cursor: pointer;\n}\n\n.concept-header:hover { background: var(--surface2); }\n\n.cn { font-family: 'Barlow Condensed', sans-serif; font-size: 32px; font-weight: 900; color: var(--border2); line-height: 1; padding-top: 3px; }\n.ct { font-family: 'Barlow Condensed', sans-serif; font-size: 20px; font-weight: 700; line-height: 1.1; margin-bottom: 6px; }\n.ch { font-size: 12px; color: var(--muted2); line-height: 1.5; }\n\n.type-badge {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 9px;\n  font-weight: 700;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  padding: 3px 8px;\n  border-radius: 2px;\n  white-space: nowrap;\n}\n\n.tb-stranger { background: rgba(232,255,0,0.1); color: var(--accent); border: 1px solid rgba(232,255,0,0.2); }\n.tb-utility { background: rgba(0,232,122,0.1); color: var(--green); border: 1px solid rgba(0,232,122,0.2); }\n.tb-conflict { background: rgba(255,60,0,0.1); color: var(--accent2); border: 1px solid rgba(255,60,0,0.2); }\n.tb-underdog { background: rgba(255,180,0,0.1); color: #ffb400; border: 1px solid rgba(255,180,0,0.2); }\n\n.concept-body {\n  display: none;\n  border-top: 1px solid var(--border);\n  padding: 20px;\n  background: var(--surface2);\n}\n\n.concept-body.open { display: block; }\n\n.cb-section { margin-bottom: 20px; }\n.cb-label {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 10px;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n  text-transform: uppercase;\n  color: var(--muted);\n  margin-bottom: 10px;\n}\n\n.thumb-block {\n  background: #000;\n  border: 1px solid rgba(232,255,0,0.3);\n  border-radius: 2px;\n  padding: 14px 16px;\n  font-size: 13px;\n  line-height: 1.6;\n  color: #ccc;\n}\n\n.hero-shot {\n  margin-top: 10px;\n  padding-top: 10px;\n  border-top: 1px solid #1a1a1a;\n  font-size: 12px;\n  color: var(--muted2);\n}\n\n.hero-shot strong { color: var(--accent); }\n\n.shot-list { list-style: none; }\n.shot-item {\n  display: flex;\n  gap: 10px;\n  align-items: flex-start;\n  padding: 9px 0;\n  border-bottom: 1px solid var(--border);\n  font-size: 13px;\n  line-height: 1.5;\n  color: #ccc;\n}\n\n.shot-item:last-child { border-bottom: none; }\n\n.shot-tag {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 9px;\n  font-weight: 700;\n  letter-spacing: 0.1em;\n  text-transform: uppercase;\n  padding: 2px 7px;\n  border-radius: 2px;\n  flex-shrink: 0;\n  margin-top: 2px;\n}\n\n.st-talking { background: rgba(232,255,0,0.1); color: var(--accent); }\n.st-broll { background: rgba(0,232,122,0.1); color: var(--green); }\n.st-sim { background: rgba(77,159,255,0.1); color: var(--blue); }\n.st-event { background: rgba(255,60,0,0.1); color: var(--accent2); }\n\n.why-works {\n  background: var(--surface3);\n  border-left: 2px solid var(--accent);\n  padding: 12px 14px;\n  font-size: 13px;\n  line-height: 1.6;\n  color: var(--muted2);\n  border-radius: 0 2px 2px 0;\n}\n\n/* LOADING */\n.loading-wrap { display: none; padding: 48px 0; text-align: center; }\n.loading-wrap.show { display: block; }\n\n.loading-bars { display: flex; gap: 4px; justify-content: center; margin-bottom: 20px; }\n.loading-bar-item {\n  width: 3px;\n  height: 24px;\n  background: var(--accent);\n  border-radius: 2px;\n  animation: barBounce 0.8s ease-in-out infinite;\n  opacity: 0.3;\n}\n\n.loading-bar-item:nth-child(1) { animation-delay: 0s; }\n.loading-bar-item:nth-child(2) { animation-delay: 0.1s; }\n.loading-bar-item:nth-child(3) { animation-delay: 0.2s; }\n.loading-bar-item:nth-child(4) { animation-delay: 0.3s; }\n.loading-bar-item:nth-child(5) { animation-delay: 0.4s; }\n\n@keyframes barBounce {\n  0%, 100% { opacity: 0.2; transform: scaleY(0.6); }\n  50% { opacity: 1; transform: scaleY(1.4); }\n}\n\n.loading-msg {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 12px;\n  letter-spacing: 0.15em;\n  text-transform: uppercase;\n  color: var(--muted2);\n}\n\n/* ERROR */\n.error-block {\n  background: rgba(255,60,0,0.08);\n  border: 1px solid rgba(255,60,0,0.25);\n  border-radius: 2px;\n  padding: 14px 16px;\n  font-size: 13px;\n  color: var(--accent2);\n  display: none;\n  margin-bottom: 16px;\n}\n\n.error-block.show { display: block; }\n\n/* SCROLLBAR */\n::-webkit-scrollbar { width: 4px; }\n\n@keyframes spin {\n  from { transform: translateY(-50%) rotate(0deg); }\n  to { transform: translateY(-50%) rotate(360deg); }\n}\n::-webkit-scrollbar-track { background: transparent; }\n::-webkit-scrollbar-thumb { background: var(--border2); border-radius: 2px; }\n\n/* CHEVRON */\n.chev { width: 16px; height: 16px; color: var(--muted); flex-shrink: 0; margin-top: 5px; transition: transform 0.2s; }\n.chev.open { transform: rotate(180deg); }\n\n.section-divider {\n  display: flex;\n  align-items: center;\n  gap: 16px;\n  margin: 32px 0 20px;\n}\n.section-divider span {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 11px;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n  text-transform: uppercase;\n  color: var(--muted);\n  white-space: nowrap;\n}\n.section-divider::before, .section-divider::after {\n  content: '';\n  flex: 1;\n  height: 1px;\n  background: var(--border);\n}\n\n.table-wrap { overflow-x: auto; }\n\n.empty-state {\n  text-align: center;\n  padding: 60px 20px;\n  color: var(--muted);\n}\n.empty-state .es-icon { font-size: 40px; margin-bottom: 12px; opacity: 0.3; }\n.empty-state .es-title { font-family: 'Barlow Condensed', sans-serif; font-size: 16px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.1em; margin-bottom: 6px; color: var(--muted2); }\n.empty-state .es-sub { font-size: 13px; line-height: 1.6; max-width: 320px; margin: 0 auto; }\n/* FORMAT BUTTONS */\n.format-btn {\n  flex: 1;\n  background: var(--surface2);\n  border: 1px solid var(--border);\n  border-radius: 2px;\n  padding: 14px 16px;\n  cursor: pointer;\n  transition: all 0.15s;\n}\n.format-btn:hover { border-color: var(--border2); }\n.format-btn.active { border-color: var(--accent); background: rgba(232,255,0,0.04); }\n.format-btn.active div:first-child { color: var(--accent); }\n\n/* STRATEGY CARDS */\n.strategy-card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 2px;\n  padding: 20px;\n}\n.strategy-card-title {\n  font-family: 'Barlow Condensed', sans-serif;\n  font-size: 11px;\n  font-weight: 700;\n  letter-spacing: 0.18em;\n  text-transform: uppercase;\n  margin-bottom: 14px;\n}\n.strategy-item {\n  display: flex;\n  gap: 10px;\n  align-items: flex-start;\n  padding: 8px 0;\n  border-bottom: 1px solid var(--border);\n  font-size: 13px;\n  line-height: 1.5;\n  color: #ccc;\n}\n.strategy-item:last-child { border-bottom: none; }\n.strategy-dot {\n  width: 5px; height: 5px;\n  border-radius: 50%;\n  margin-top: 5px;\n  flex-shrink: 0;\n}\n\n/* CHAT MESSAGES */\n.chat-msg {\n  margin-bottom: 12px;\n  font-size: 13px;\n  line-height: 1.6;\n}\n.chat-msg-user {\n  background: rgba(232,255,0,0.05);\n  border: 1px solid rgba(232,255,0,0.1);\n  border-radius: 2px;\n  padding: 10px 12px;\n  color: var(--accent);\n  font-size: 12px;\n}\n.chat-msg-ai {\n  color: var(--muted2);\n  font-size: 12px;\n  padding: 4px 0;\n}\n\n@media (max-width: 700px) {\n  #strategyCards { grid-template-columns: 1fr !important; }\n}\n"

const bodyHtml = "<nav class=\"nav\">\n  <div class=\"nav-brand\">Formula Zac</div>\n  <div class=\"nav-tab active\" onclick=\"showPage('upload')\">Channel Data</div>\n  <div class=\"nav-tab\" onclick=\"showPage('insights')\" id=\"tab-insights\">Insights</div>\n  <div class=\"nav-tab\" onclick=\"showPage('retention')\" id=\"tab-retention\">Retention</div>\n  <div class=\"nav-tab\" onclick=\"showPage('generate')\" id=\"tab-generate\">Generate</div>\n  <div class=\"nav-status\">\n    <div class=\"status-dot\" id=\"statusDot\"></div>\n    <span id=\"statusText\">No data loaded</span>\n  </div>\n</nav>\n\n<!-- UPLOAD PAGE -->\n<div class=\"page active\" id=\"page-upload\">\n  <div class=\"page-title\">Step 1</div>\n  <div class=\"page-heading\">Connect Your<br>Channel</div>\n  <p class=\"page-sub\">Sign in with YouTube to automatically pull your analytics, transcripts and comments \u2014 no CSV needed.</p>\n\n  <!-- NOT LOGGED IN -->\n  <div id=\"loginSection\">\n    <div class=\"card\" style=\"margin-bottom:16px;text-align:center;padding:48px 32px\">\n      <div style=\"font-size:48px;margin-bottom:16px;opacity:0.6\">\u25b6</div>\n      <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:24px;font-weight:900;text-transform:uppercase;letter-spacing:0.05em;margin-bottom:8px\">Connect YouTube</div>\n      <div style=\"font-size:14px;color:var(--muted2);margin-bottom:28px;line-height:1.6;max-width:400px;margin-left:auto;margin-right:auto\">Grants read-only access to your analytics and comments. Nothing is posted or modified.</div>\n      <a href=\"/api/auth/login\" class=\"btn btn-primary\" style=\"display:inline-flex;text-decoration:none;font-size:16px;padding:16px 40px\">\n        Sign in with Google \u2192\n      </a>\n    </div>\n\n    <div style=\"margin-top:24px\">\n      <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:11px;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:14px\">Or upload manually</div>\n      <div class=\"card\">\n        <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:14px\">\n          <div class=\"card-label\" style=\"margin-bottom:0\">YouTube Studio CSV Export</div>\n          <div style=\"display:flex;align-items:center;gap:6px;font-family:'Barlow Condensed',sans-serif;font-size:11px;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--green)\">\n            <div style=\"width:6px;height:6px;border-radius:50%;background:var(--green);box-shadow:0 0 6px var(--green)\"></div>\n            Transcript Fetching Ready\n          </div>\n        </div>\n        <div class=\"upload-zone\" id=\"uploadZone\" style=\"padding:20px 24px;cursor:pointer;position:relative\">\n          <input type=\"file\" id=\"csvInput\" accept=\".csv,.zip\" onchange=\"handleFileUpload(event)\" style=\"position:absolute;inset:0;opacity:0;cursor:pointer;width:100%;height:100%\">\n          <div style=\"display:flex;align-items:center;gap:12px\">\n            <div style=\"font-size:24px;opacity:0.4\">\ud83d\udcca</div>\n            <div>\n              <div class=\"upload-title\" style=\"font-size:14px;margin-bottom:2px\">Drop CSV or ZIP here</div>\n              <div class=\"upload-hint\">Analytics \u2192 Advanced Mode \u2192 Export \u2192 CSV</div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- LOGGED IN -->\n  <div id=\"connectedSection\" style=\"display:none\">\n    <div class=\"card\" style=\"margin-bottom:16px;border-color:rgba(0,232,122,0.3);background:rgba(0,232,122,0.03)\">\n      <div style=\"display:flex;align-items:center;gap:16px\">\n        <img id=\"userAvatar\" src=\"\" style=\"width:40px;height:40px;border-radius:50%;display:none\">\n        <div>\n          <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.1em;color:var(--green);margin-bottom:2px\">Connected</div>\n          <div style=\"font-size:13px;color:var(--muted2)\" id=\"userEmail\"></div>\n        </div>\n        <div style=\"display:flex;gap:8px;margin-left:auto\">\n          <button class=\"btn btn-secondary\" style=\"font-size:11px;padding:8px 16px\" onclick=\"refreshData()\">\u21bb Refresh</button>\n          <button class=\"btn btn-secondary\" style=\"font-size:11px;padding:8px 16px\" onclick=\"disconnectGoogle()\">Disconnect</button>\n        </div>\n      </div>\n    </div>\n\n    <div id=\"uploadProgress\" style=\"display:none\">\n      <div class=\"progress-wrap\">\n        <div class=\"progress-label\"><span id=\"progressLabel\">Loading your channel...</span><span id=\"progressPct\">0%</span></div>\n        <div class=\"progress-bar\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\n      </div>\n    </div>\n\n    <div id=\"transcriptStatus\" style=\"display:none;margin-bottom:16px\">\n      <div class=\"card\">\n        <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:14px\">\n          <div class=\"card-label\" style=\"margin-bottom:0\">Transcript Fetch \u2014 Top 10 Long Form</div>\n          <div style=\"font-size:11px;color:var(--muted)\">Used to deepen channel DNA analysis</div>\n        </div>\n        <div id=\"transcriptRows\"></div>\n        <div style=\"margin-top:12px;padding-top:12px;border-top:1px solid var(--border);font-size:12px;line-height:1.5\" id=\"transcriptSummary\"></div>\n      </div>\n    </div>\n\n    <div id=\"uploadSuccess\" style=\"display:none\">\n      <div class=\"card\" style=\"border-color:rgba(0,232,122,0.3);background:rgba(0,232,122,0.03)\">\n        <div style=\"display:flex;align-items:center;gap:12px\">\n          <div style=\"font-size:24px\">\u2713</div>\n          <div>\n            <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.1em;color:var(--green);margin-bottom:3px\">Channel Loaded</div>\n            <div style=\"font-size:13px;color:var(--muted2)\" id=\"uploadSummary\"></div>\n          </div>\n          <button class=\"btn btn-primary\" style=\"margin-left:auto\" onclick=\"showPage('insights')\">View Insights \u2192</button>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- CSV upload progress (shown when using manual upload) -->\n  <div id=\"csvUploadProgress\" style=\"display:none;margin-top:16px\">\n    <div class=\"progress-wrap\">\n      <div class=\"progress-label\"><span id=\"progressLabel\">Processing...</span><span id=\"progressPct\">0%</span></div>\n      <div class=\"progress-bar\"><div class=\"progress-fill\" id=\"progressFill\" style=\"width:0%\"></div></div>\n    </div>\n  </div>\n  <div id=\"csvTranscriptStatus\" style=\"display:none;margin-bottom:16px\">\n    <div class=\"card\">\n      <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:14px\">\n        <div class=\"card-label\" style=\"margin-bottom:0\">Transcript Fetch \u2014 Top 10 Long Form</div>\n        <div style=\"font-size:11px;color:var(--muted)\">Used to deepen channel DNA analysis</div>\n      </div>\n      <div id=\"transcriptRows\"></div>\n      <div style=\"margin-top:12px;padding-top:12px;border-top:1px solid var(--border);font-size:12px;line-height:1.5\" id=\"transcriptSummary\"></div>\n    </div>\n  </div>\n  <div id=\"csvUploadSuccess\" style=\"display:none\">\n    <div class=\"card\" style=\"border-color:rgba(0,232,122,0.3);background:rgba(0,232,122,0.03)\">\n      <div style=\"display:flex;align-items:center;gap:12px\">\n        <div style=\"font-size:24px\">\u2713</div>\n        <div>\n          <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.1em;color:var(--green);margin-bottom:3px\">Data Loaded</div>\n          <div style=\"font-size:13px;color:var(--muted2)\" id=\"uploadSummary\"></div>\n        </div>\n        <button class=\"btn btn-primary\" style=\"margin-left:auto\" onclick=\"showPage('insights')\">View Insights \u2192</button>\n      </div>\n    </div>\n  </div>\n\n  <div style=\"margin-top:32px\" id=\"exportInstructions\">\n    <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:11px;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:14px\">How to export from YouTube Studio</div>\n    <div style=\"display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px\">\n      <div class=\"card\"><div class=\"card-label\">01</div><div style=\"font-size:13px;color:#ccc;line-height:1.6\">Go to <strong style=\"color:var(--text)\">YouTube Studio \u2192 Analytics</strong></div></div>\n      <div class=\"card\"><div class=\"card-label\">02</div><div style=\"font-size:13px;color:#ccc;line-height:1.6\">Click <strong style=\"color:var(--text)\">Advanced Mode</strong> (bottom right)</div></div>\n      <div class=\"card\"><div class=\"card-label\">03</div><div style=\"font-size:13px;color:#ccc;line-height:1.6\">Set date to <strong style=\"color:var(--text)\">Lifetime</strong>, hit <strong style=\"color:var(--text)\">Export \u2192 CSV</strong></div></div>\n      <div class=\"card\"><div class=\"card-label\">04</div><div style=\"font-size:13px;color:#ccc;line-height:1.6\">Upload the <strong style=\"color:var(--text)\">ZIP</strong> or <strong style=\"color:var(--text)\">\"Table data.csv\"</strong> here</div></div>\n    </div>\n  </div>\n</div>\n\n<!-- INSIGHTS PAGE -->\n<div class=\"page\" id=\"page-insights\">\n  <div class=\"page-title\">Step 2</div>\n  <div class=\"page-heading\">Channel<br>Intelligence</div>\n  <p class=\"page-sub\">AI analysis of what's actually working on your channel \u2014 and what isn't.</p>\n\n  <div id=\"insightsEmpty\" class=\"empty-state\">\n    <div class=\"es-icon\">\ud83d\udcc8</div>\n    <div class=\"es-title\">No data yet</div>\n    <div class=\"es-sub\">Upload your YouTube Studio CSV on the Channel Data tab first.</div>\n  </div>\n\n  <div id=\"insightsContent\" style=\"display:none\">\n    <div class=\"stats-grid\" id=\"statsGrid\"></div>\n\n    <!-- AI STRATEGY SECTION -->\n    <div class=\"section-divider\"><span>AI Strategy Brief</span></div>\n    <div id=\"strategyLoading\" style=\"text-align:center;padding:40px 0;display:none\">\n      <div class=\"loading-bars\" style=\"justify-content:center;margin-bottom:16px\">\n        <div class=\"loading-bar-item\"></div><div class=\"loading-bar-item\"></div>\n        <div class=\"loading-bar-item\"></div><div class=\"loading-bar-item\"></div>\n        <div class=\"loading-bar-item\"></div>\n      </div>\n      <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:12px;letter-spacing:0.15em;text-transform:uppercase;color:var(--muted2)\">Analysing your channel...</div>\n    </div>\n    <div id=\"strategyContent\" style=\"display:none\">\n      <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px\" id=\"strategyCards\"></div>\n      <div class=\"card\" id=\"strategyDeep\" style=\"margin-bottom:32px\"></div>\n    </div>\n\n    <div class=\"section-divider\"><span>Thumbnail Intelligence</span></div>\n    <div id=\"thumbnailInsightsEmpty\" style=\"display:none;padding:20px 0;font-size:13px;color:var(--muted)\">No thumbnail analysis available \u2014 connect YouTube to enable vision analysis.</div>\n    <div id=\"thumbnailInsightsContent\" style=\"display:none;margin-bottom:32px\">\n      <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px\" id=\"thumbnailCards\"></div>\n      <div class=\"card\" id=\"thumbnailRecommendation\"></div>\n    </div>\n\n    <div class=\"section-divider\"><span>Performance Data</span></div>\n    <div class=\"insights-grid\" id=\"insightsGrid\"></div>\n\n    <div class=\"section-divider\"><span>Long Form</span></div>\n    <div class=\"table-wrap\">\n      <table class=\"video-table\" id=\"longsTable\"></table>\n    </div>\n\n    <div class=\"section-divider\"><span>Shorts</span></div>\n    <div class=\"table-wrap\">\n      <table class=\"video-table\" id=\"shortsTable\"></table>\n    </div>\n  </div>\n</div>\n\n\n\n<!-- RETENTION PAGE -->\n<div class=\"page\" id=\"page-retention\">\n  <div class=\"page-title\">Step 4</div>\n  <div class=\"page-heading\">Retention<br>Analysis</div>\n  <p class=\"page-sub\">Pick any video to see how your intro performed and exactly what in the script caused viewers to leave.</p>\n\n  <div id=\"retentionEmpty\" class=\"empty-state\">\n    <div class=\"es-icon\">\ud83d\udcc9</div>\n    <div class=\"es-title\">No data yet</div>\n    <div class=\"es-sub\">Connect YouTube and load your channel data first.</div>\n  </div>\n\n  <div id=\"retentionContent\" style=\"display:none\">\n    <!-- Video selector -->\n    <div class=\"card\" style=\"margin-bottom:20px\">\n      <div class=\"card-label\" style=\"margin-bottom:12px\">Select a video to analyse</div>\n      <select id=\"retentionVideoSelect\" style=\"width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:2px;color:var(--text);font-family:'Barlow',sans-serif;font-size:14px;padding:12px;outline:none;cursor:pointer\" onchange=\"loadRetentionForVideo(this.value)\">\n        <option value=\"\">\u2014 Choose a video \u2014</option>\n      </select>\n    </div>\n\n    <!-- Loading state -->\n    <div id=\"retentionLoading\" style=\"display:none;text-align:center;padding:48px 0\">\n      <div class=\"loading-bars\" style=\"justify-content:center;margin-bottom:16px\">\n        <div class=\"loading-bar-item\"></div><div class=\"loading-bar-item\"></div>\n        <div class=\"loading-bar-item\"></div><div class=\"loading-bar-item\"></div>\n        <div class=\"loading-bar-item\"></div>\n      </div>\n      <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:12px;letter-spacing:0.15em;text-transform:uppercase;color:var(--muted2)\" id=\"retentionLoadingMsg\">Fetching retention data...</div>\n    </div>\n\n    <!-- Results -->\n    <div id=\"retentionResults\" style=\"display:none\">\n      <!-- Retention curve -->\n      <div class=\"card\" style=\"margin-bottom:16px\">\n        <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:16px\">\n          <div class=\"card-label\" style=\"margin-bottom:0\">Retention Curve</div>\n          <div style=\"display:flex;gap:16px;font-size:12px;color:var(--muted2)\" id=\"retentionStats\"></div>\n        </div>\n        <div style=\"position:relative;height:120px;background:var(--surface2);border-radius:2px;overflow:hidden\">\n          <canvas id=\"retentionCanvas\" style=\"width:100%;height:100%\"></canvas>\n          <!-- Intro zone marker -->\n          <div style=\"position:absolute;top:0;left:0;width:10%;height:100%;background:rgba(232,255,0,0.05);border-right:1px dashed rgba(232,255,0,0.3)\"></div>\n          <div style=\"position:absolute;top:4px;left:1%;font-family:'Barlow Condensed',sans-serif;font-size:9px;letter-spacing:0.1em;text-transform:uppercase;color:rgba(232,255,0,0.5)\">Intro</div>\n        </div>\n        <div style=\"display:flex;justify-content:space-between;font-size:11px;color:var(--muted);margin-top:6px\">\n          <span>0%</span><span>25%</span><span>50%</span><span>75%</span><span>100%</span>\n        </div>\n      </div>\n\n      <!-- Intro grade -->\n      <div style=\"display:grid;grid-template-columns:auto 1fr;gap:16px;margin-bottom:16px;align-items:start\">\n        <div class=\"card\" style=\"text-align:center;padding:24px 32px\">\n          <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:64px;font-weight:900;line-height:1\" id=\"introGrade\">\u2014</div>\n          <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:10px;font-weight:700;letter-spacing:0.15em;text-transform:uppercase;color:var(--muted);margin-top:4px\">Intro Grade</div>\n        </div>\n        <div class=\"card\">\n          <div class=\"card-label\" style=\"margin-bottom:6px\">Verdict</div>\n          <div style=\"font-size:15px;font-weight:500;color:var(--text);margin-bottom:12px\" id=\"introVerdict\"></div>\n          <div class=\"card-label\" style=\"margin-bottom:6px\">Diagnosis</div>\n          <div style=\"font-size:13px;color:#ccc;line-height:1.7\" id=\"introDiagnosis\"></div>\n        </div>\n      </div>\n\n      <!-- Details grid -->\n      <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px\">\n        <div class=\"card\">\n          <div class=\"card-label\" style=\"color:var(--accent);margin-bottom:8px\">Hook Promise Check</div>\n          <div style=\"font-size:13px;color:#ccc;line-height:1.6\" id=\"hookPromiseCheck\"></div>\n        </div>\n        <div class=\"card\">\n          <div class=\"card-label\" style=\"color:var(--blue);margin-bottom:8px\">Mid-Video Shape</div>\n          <div style=\"font-size:13px;color:#ccc;line-height:1.6\" id=\"midVideoShape\"></div>\n        </div>\n        <div class=\"card\" style=\"border-color:rgba(255,60,0,0.3)\">\n          <div class=\"card-label\" style=\"color:var(--accent2);margin-bottom:8px\">Biggest Fix</div>\n          <div style=\"font-size:13px;color:#ccc;line-height:1.6\" id=\"biggestFix\"></div>\n        </div>\n        <div class=\"card\" style=\"border-color:rgba(0,232,122,0.3)\">\n          <div class=\"card-label\" style=\"color:var(--green);margin-bottom:8px\">What Worked</div>\n          <div style=\"font-size:13px;color:#ccc;line-height:1.6\" id=\"whatWorked\"></div>\n        </div>\n      </div>\n\n      <!-- Intro script section -->\n      <div class=\"card\">\n        <div class=\"card-label\" style=\"margin-bottom:10px\">Intro Script (first 15% of video)</div>\n        <div id=\"introScriptText\" style=\"font-size:13px;color:var(--muted2);line-height:1.8;font-style:italic;border-left:2px solid var(--border);padding-left:14px\"></div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<!-- GENERATE PAGE -->\n<div class=\"page\" id=\"page-generate\">\n  <div class=\"page-title\">Step 3</div>\n  <div class=\"page-heading\">Generate<br>Scripts</div>\n  <p class=\"page-sub\">Dump your notes, pick your format, get a full script. Then refine it in the chat below.</p>\n\n  <div class=\"gen-layout\">\n    <div>\n      <!-- INPUT CARD -->\n      <div id=\"genInputSection\">\n        <div class=\"card\" style=\"margin-bottom:12px\">\n          <div class=\"card-label\" style=\"margin-bottom:12px\">What happened? Dump everything.</div>\n          <textarea id=\"notesInput\" placeholder=\"e.g. Just got back from The Bend. Qualifying went badly \u2014 traffic everywhere, couldn't get a clean lap. Made a setup change overnight, came back P3 in race 1. Then in race 2 someone tagged me at turn 1...\"></textarea>\n          <div style=\"font-size:12px;color:var(--muted);margin-top:8px;line-height:1.5\">More detail = better output. Results, what went wrong, what went right, behind-the-scenes, technical stuff \u2014 don't filter it.</div>\n        </div>\n\n        <div class=\"card\" style=\"margin-bottom:16px\">\n          <div class=\"card-label\" style=\"margin-bottom:12px\">Video Format</div>\n          <div style=\"display:flex;gap:10px\">\n            <div class=\"format-btn active\" id=\"fmtLong\" onclick=\"selectFormat('long')\">\n              <div style=\"font-family:'Barlow Condensed',sans-serif;font-weight:700;font-size:16px;margin-bottom:2px\">Long Form</div>\n              <div style=\"font-size:11px;color:var(--muted2)\">5\u201320 min \u00b7 full story arc \u00b7 script + shot list</div>\n            </div>\n            <div class=\"format-btn\" id=\"fmtShort\" onclick=\"selectFormat('short')\">\n              <div style=\"font-family:'Barlow Condensed',sans-serif;font-weight:700;font-size:16px;margin-bottom:2px\">Short</div>\n              <div style=\"font-size:11px;color:var(--muted2)\">&lt;60 sec \u00b7 hook + payoff \u00b7 caption + visual brief</div>\n            </div>\n          </div>\n        </div>\n\n        <div class=\"error-block\" id=\"genError\"></div>\n        <button class=\"btn btn-primary btn-lg\" id=\"genBtn\" onclick=\"generateConcepts()\">Generate \u2192</button>\n      </div>\n\n      <div class=\"loading-wrap\" id=\"genLoading\">\n        <div class=\"loading-bars\">\n          <div class=\"loading-bar-item\"></div><div class=\"loading-bar-item\"></div>\n          <div class=\"loading-bar-item\"></div><div class=\"loading-bar-item\"></div>\n          <div class=\"loading-bar-item\"></div>\n        </div>\n        <div class=\"loading-msg\" id=\"loadingMsg\">Analysing your story...</div>\n      </div>\n\n      <!-- CONCEPTS LIST -->\n      <div id=\"conceptsOutput\" style=\"margin-top:24px\"></div>\n\n      <!-- SCRIPT PANEL -->\n      <div id=\"scriptPanel\" style=\"display:none;margin-top:24px\">\n        <div class=\"section-divider\"><span id=\"scriptPanelTitle\">Full Script</span></div>\n        <div class=\"card\" style=\"margin-bottom:16px\">\n          <div id=\"scriptContent\" style=\"font-size:13px;line-height:1.8;color:#ccc;white-space:pre-wrap\"></div>\n        </div>\n\n        <!-- REFINE CHAT -->\n        <div class=\"card\" style=\"margin-bottom:8px\">\n          <div class=\"card-label\" style=\"margin-bottom:10px\">Refine this script</div>\n          <div id=\"chatHistory\" style=\"margin-bottom:12px;max-height:300px;overflow-y:auto\"></div>\n          <div style=\"display:flex;gap:8px\">\n            <input type=\"text\" id=\"refineInput\" placeholder=\"e.g. Make the hook punchier, cut the tyre section, add more about the comeback...\" style=\"flex:1;background:var(--surface2);border:1px solid var(--border);border-radius:2px;color:var(--text);font-family:'Barlow',sans-serif;font-size:13px;padding:10px 12px;outline:none;transition:border-color 0.2s\" onfocus=\"this.style.borderColor='var(--accent)'\" onblur=\"this.style.borderColor='var(--border)'\" onkeydown=\"if(event.key==='Enter')refineScript()\">\n            <button class=\"btn btn-primary\" onclick=\"refineScript()\" id=\"refineBtn\" style=\"white-space:nowrap\">Refine \u2192</button>\n          </div>\n        </div>\n        <button class=\"btn btn-secondary\" onclick=\"resetGenerate()\" style=\"font-size:11px\">\u2190 New Video</button>\n      </div>\n    </div>\n\n    <div>\n      <div class=\"dna-panel\" id=\"dnaPanel\">\n        <div class=\"dna-title\"><div class=\"dna-dot\"></div> Channel DNA</div>\n        <div class=\"dna-content\" id=\"dnaContent\">\n          <span style=\"color:var(--muted)\">Upload your YouTube data to unlock channel-specific generation.</span>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n\n\n\n<!-- GENERATE PAGE -->\n<div class=\"page\" id=\"page-generate\">\n  <div class=\"page-title\">Step 3</div>\n  <div class=\"page-heading\">Generate<br>Scripts</div>\n  <p class=\"page-sub\">Dump your notes, pick your format, get a full script. Then refine it in the chat below.</p>\n\n  <div class=\"gen-layout\">\n    <div>\n      <!-- INPUT CARD -->\n      <div id=\"genInputSection\">\n        <div class=\"card\" style=\"margin-bottom:12px\">\n          <div class=\"card-label\" style=\"margin-bottom:12px\">What happened? Dump everything.</div>\n          <textarea id=\"notesInput\" placeholder=\"e.g. Just got back from The Bend. Qualifying went badly \u2014 traffic everywhere, couldn't get a clean lap. Made a setup change overnight, came back P3 in race 1. Then in race 2 someone tagged me at turn 1...\"></textarea>\n          <div style=\"font-size:12px;color:var(--muted);margin-top:8px;line-height:1.5\">More detail = better output. Results, what went wrong, what went right, behind-the-scenes, technical stuff \u2014 don't filter it.</div>\n        </div>\n\n        <div class=\"card\" style=\"margin-bottom:16px\">\n          <div class=\"card-label\" style=\"margin-bottom:12px\">Video Format</div>\n          <div style=\"display:flex;gap:10px\">\n            <div class=\"format-btn active\" id=\"fmtLong\" onclick=\"selectFormat('long')\">\n              <div style=\"font-family:'Barlow Condensed',sans-serif;font-weight:700;font-size:16px;margin-bottom:2px\">Long Form</div>\n              <div style=\"font-size:11px;color:var(--muted2)\">5\u201320 min \u00b7 full story arc \u00b7 script + shot list</div>\n            </div>\n            <div class=\"format-btn\" id=\"fmtShort\" onclick=\"selectFormat('short')\">\n              <div style=\"font-family:'Barlow Condensed',sans-serif;font-weight:700;font-size:16px;margin-bottom:2px\">Short</div>\n              <div style=\"font-size:11px;color:var(--muted2)\">&lt;60 sec \u00b7 hook + payoff \u00b7 caption + visual brief</div>\n            </div>\n          </div>\n        </div>\n\n        <div class=\"error-block\" id=\"genError\"></div>\n        <button class=\"btn btn-primary btn-lg\" id=\"genBtn\" onclick=\"generateConcepts()\">Generate \u2192</button>\n      </div>\n\n      <div class=\"loading-wrap\" id=\"genLoading\">\n        <div class=\"loading-bars\">\n          <div class=\"loading-bar-item\"></div><div class=\"loading-bar-item\"></div>\n          <div class=\"loading-bar-item\"></div><div class=\"loading-bar-item\"></div>\n          <div class=\"loading-bar-item\"></div>\n        </div>\n        <div class=\"loading-msg\" id=\"loadingMsg\">Analysing your story...</div>\n      </div>\n\n      <!-- CONCEPTS LIST -->\n      <div id=\"conceptsOutput\" style=\"margin-top:24px\"></div>\n\n      <!-- SCRIPT PANEL -->\n      <div id=\"scriptPanel\" style=\"display:none;margin-top:24px\">\n        <div class=\"section-divider\"><span id=\"scriptPanelTitle\">Full Script</span></div>\n        <div class=\"card\" style=\"margin-bottom:16px\">\n          <div id=\"scriptContent\" style=\"font-size:13px;line-height:1.8;color:#ccc;white-space:pre-wrap\"></div>\n        </div>\n\n        <!-- REFINE CHAT -->\n        <div class=\"card\" style=\"margin-bottom:8px\">\n          <div class=\"card-label\" style=\"margin-bottom:10px\">Refine this script</div>\n          <div id=\"chatHistory\" style=\"margin-bottom:12px;max-height:300px;overflow-y:auto\"></div>\n          <div style=\"display:flex;gap:8px\">\n            <input type=\"text\" id=\"refineInput\" placeholder=\"e.g. Make the hook punchier, cut the tyre section, add more about the comeback...\" style=\"flex:1;background:var(--surface2);border:1px solid var(--border);border-radius:2px;color:var(--text);font-family:'Barlow',sans-serif;font-size:13px;padding:10px 12px;outline:none;transition:border-color 0.2s\" onfocus=\"this.style.borderColor='var(--accent)'\" onblur=\"this.style.borderColor='var(--border)'\" onkeydown=\"if(event.key==='Enter')refineScript()\">\n            <button class=\"btn btn-primary\" onclick=\"refineScript()\" id=\"refineBtn\" style=\"white-space:nowrap\">Refine \u2192</button>\n          </div>\n        </div>\n        <button class=\"btn btn-secondary\" onclick=\"resetGenerate()\" style=\"font-size:11px\">\u2190 New Video</button>\n      </div>\n    </div>\n\n    <div>\n      <div class=\"dna-panel\" id=\"dnaPanel\">\n        <div class=\"dna-title\"><div class=\"dna-dot\"></div> Channel DNA</div>\n        <div class=\"dna-content\" id=\"dnaContent\">\n          <span style=\"color:var(--muted)\">Upload your YouTube data to unlock channel-specific generation.</span>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<script>\n// \u2500\u2500\u2500 STATE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlet channelData = null;\nlet channelDNA = null;\nlet googleAccessToken = null;\n\n// \u2500\u2500\u2500 OAUTH INIT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction initOAuth() {\n  const params = new URLSearchParams(window.location.search);\n  const accessToken = params.get('access_token');\n  const error = params.get('error');\n  if (error) { console.error('OAuth error:', error); return; }\n  if (accessToken) {\n    localStorage.setItem('google_access_token', accessToken);\n    localStorage.setItem('user_name', params.get('name') || '');\n    localStorage.setItem('user_email', params.get('email') || '');\n    localStorage.setItem('user_picture', params.get('picture') || '');\n    window.history.replaceState({}, '', '/');\n  }\n  const storedToken = localStorage.getItem('google_access_token');\n  if (storedToken) {\n    googleAccessToken = storedToken;\n    showConnectedState();\n    // Load from cache first \u2014 only fetch fresh if no cache exists\n    if (!loadFromCache()) {\n      loadYouTubeData();\n    }\n  }\n}\n\nfunction showConnectedState() {\n  document.getElementById('loginSection').style.display = 'none';\n  document.getElementById('connectedSection').style.display = 'block';\n  document.getElementById('exportInstructions').style.display = 'none';\n  const email = localStorage.getItem('user_email');\n  const picture = localStorage.getItem('user_picture');\n  const name = localStorage.getItem('user_name');\n  if (email) document.getElementById('userEmail').textContent = name || email;\n  if (picture) { const a = document.getElementById('userAvatar'); a.src = picture; a.style.display = 'block'; }\n}\n\nfunction refreshData() {\n  localStorage.removeItem('channel_cache');\n  loadYouTubeData();\n}\n\nfunction disconnectGoogle() {\n  localStorage.removeItem(\"google_access_token\"); localStorage.removeItem(\"user_name\"); localStorage.removeItem(\"user_email\"); localStorage.removeItem(\"user_picture\"); localStorage.removeItem(\"channel_cache\");\n  googleAccessToken = null;\n  document.getElementById('loginSection').style.display = 'block';\n  document.getElementById('connectedSection').style.display = 'none';\n  document.getElementById('exportInstructions').style.display = 'block';\n  document.getElementById('uploadSuccess').style.display = 'none';\n  document.getElementById('uploadProgress').style.display = 'none';\n  document.getElementById('transcriptStatus').style.display = 'none';\n  channelData = null; channelDNA = null;\n}\n\nasync function loadYouTubeData() {\n  if (!googleAccessToken) return;\n  document.getElementById('uploadProgress').style.display = 'block';\n  document.getElementById('uploadSuccess').style.display = 'none';\n  setProgress(10, 'Connecting to YouTube...');\n  try {\n    setProgress(20, 'Loading your videos...');\n    const res = await fetch(`/api/youtube-data?access_token=${encodeURIComponent(googleAccessToken)}`);\n    if (!res.ok) { const err = await res.json(); throw new Error(err.error || 'Failed'); }\n    const { videos, channelId } = await res.json();\n    window._channelId = channelId; // store for retention API calls\n    setProgress(50, `Found ${videos.length} videos. Fetching transcripts...`);\n\n    const longs = videos.filter(v => !v.isShort).sort((a,b) => b.views - a.views).slice(0, 10);\n    let fetched = 0;\n    document.getElementById('transcriptStatus').style.display = 'block';\n    const tRows = document.getElementById('transcriptRows');\n    tRows.innerHTML = '';\n    const tResults = [];\n\n    for (const vid of longs) {\n      const row = document.createElement('div');\n      row.style.cssText = 'padding:8px 0;border-bottom:1px solid var(--border);';\n      row.innerHTML = `<div style=\"display:flex;align-items:center;gap:10px;margin-bottom:4px\"><div style=\"width:8px;height:8px;border-radius:50%;background:var(--border2);flex-shrink:0\" id=\"tdot-${vid.id}\"></div><div style=\"flex:1;font-size:12px;color:var(--muted2);white-space:nowrap;overflow:hidden;text-overflow:ellipsis\">${vid.title.slice(0,60)}...</div><div style=\"font-family:'Barlow Condensed',sans-serif;font-size:10px;letter-spacing:0.1em;text-transform:uppercase;flex-shrink:0;color:var(--muted)\" id=\"tstatus-${vid.id}\">Queued</div></div><div style=\"height:2px;background:var(--border);border-radius:1px;overflow:hidden\"><div id=\"tbar-${vid.id}\" style=\"height:100%;width:0%;background:var(--accent);border-radius:1px;transition:width 0.4s ease\"></div></div>`;\n      tRows.appendChild(row);\n    }\n\n    for (const vid of longs) {\n      if (fetched > 0) { document.getElementById('tstatus-'+vid.id).textContent='Waiting...'; await new Promise(r=>setTimeout(r,4000)); }\n      document.getElementById('tdot-'+vid.id).style.background='var(--accent)';\n      document.getElementById('tdot-'+vid.id).style.boxShadow='0 0 6px var(--accent)';\n      document.getElementById('tstatus-'+vid.id).style.color='var(--accent)';\n      document.getElementById('tstatus-'+vid.id).textContent='Fetching...';\n      document.getElementById('tbar-'+vid.id).style.width='60%';\n      try {\n        let transcript;\n        try { transcript = await fetchTranscript(vid.id); }\n        catch(re) { if(re.message?.includes('429')){ await new Promise(r=>setTimeout(r,5000)); transcript=await fetchTranscript(vid.id); } else throw re; }\n        vid.transcript = transcript;\n        document.getElementById('tbar-'+vid.id).style.cssText='height:100%;width:100%;background:var(--green);border-radius:1px;transition:width 0.4s ease';\n        document.getElementById('tdot-'+vid.id).style.cssText='width:8px;height:8px;border-radius:50%;background:var(--green);box-shadow:0 0 6px var(--green);flex-shrink:0';\n        document.getElementById('tstatus-'+vid.id).style.color='var(--green)';\n        document.getElementById('tstatus-'+vid.id).textContent=`\u2713 ~${Math.round(transcript.split(' ').length)} words`;\n        tResults.push({ok:true});\n      } catch(err) {\n        vid.transcript=null;\n        document.getElementById('tbar-'+vid.id).style.cssText='height:100%;width:100%;background:var(--accent2);border-radius:1px';\n        document.getElementById('tdot-'+vid.id).style.cssText='width:8px;height:8px;border-radius:50%;background:var(--accent2);flex-shrink:0';\n        document.getElementById('tstatus-'+vid.id).style.color='var(--accent2)';\n        document.getElementById('tstatus-'+vid.id).textContent='\u2717 '+(err.message||'Failed');\n        tResults.push({ok:false});\n      }\n      fetched++;\n      setProgress(50+Math.round((fetched/longs.length)*25), `Transcripts: ${fetched}/${longs.length}`);\n    }\n\n    // Fetch comments for top 5\n    setProgress(80, 'Fetching comments...');\n    for (const vid of longs.slice(0,5)) {\n      try {\n        const cr = await fetch(`/api/comments?access_token=${encodeURIComponent(googleAccessToken)}&video_id=${vid.id}`);\n        if (cr.ok) { const {comments} = await cr.json(); vid.comments = comments; }\n      } catch(e) { vid.comments = []; }\n    }\n\n    // Run thumbnail vision analysis\n    setProgress(85, 'Analysing thumbnails...');\n    let thumbnailAnalysis = null;\n    try {\n      const thumbRes = await fetch('/api/thumbnail-analysis', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({ videos: videos.filter(v => !v.isShort).slice(0, 12) })\n      });\n      if (thumbRes.ok) {\n        const thumbData = await thumbRes.json();\n        thumbnailAnalysis = thumbData.analysis;\n      }\n    } catch(e) { console.log('Thumbnail analysis failed:', e.message); }\n\n    setProgress(90, 'Analysing channel patterns...');\n    channelData = videos;\n    const dna = await buildChannelDNA(videos, thumbnailAnalysis);\n    channelDNA = dna;\n    setProgress(100, 'Done!');\n    renderInsights(videos, thumbnailAnalysis);\n    renderDNA(dna);\n    populateRetentionSelector(videos);\n    updateStatus(videos.length);\n    document.getElementById('uploadProgress').style.display = 'none';\n    document.getElementById('uploadSuccess').style.display = 'block';\n    const lf = videos.filter(v=>!v.isShort).length;\n    const sh = videos.filter(v=>v.isShort).length;\n    const gotT = tResults.filter(r=>r.ok).length;\n    document.getElementById('uploadSummary').textContent = `${videos.length} videos \u2014 ${lf} long form, ${sh} shorts \u2014 ${gotT} transcripts`;\n\n    // Cache channel data so we don't re-fetch on next visit\n    try {\n      localStorage.setItem('channel_cache', JSON.stringify({\n        videos: videos.map(v => ({...v, transcript: v.transcript?.slice(0, 2000) || null, comments: v.comments?.slice(0,20) || []})),\n        dna: dna,\n        cachedAt: new Date().toISOString()\n      }));\n    } catch(e) { console.log('Cache too large, skipping'); }\n\n  } catch(err) {\n    setProgress(0, 'Error: ' + err.message);\n    console.error(err);\n  }\n}\n\nfunction loadFromCache() {\n  try {\n    const cached = localStorage.getItem('channel_cache');\n    if (!cached) return false;\n    const { videos, dna, cachedAt } = JSON.parse(cached);\n    if (!videos || !videos.length) return false;\n\n    channelData = videos;\n    channelDNA = dna;\n    renderInsights(videos);\n    renderDNA(dna);\n    updateStatus(videos.length);\n\n    const lf = videos.filter(v=>!v.isShort).length;\n    const sh = videos.filter(v=>v.isShort).length;\n    const gotT = videos.filter(v=>v.transcript).length;\n    const cacheDate = new Date(cachedAt).toLocaleDateString('en-AU', {day:'numeric',month:'short',hour:'2-digit',minute:'2-digit'});\n    document.getElementById('uploadSuccess').style.display = 'block';\n    document.getElementById('uploadSummary').textContent = `${videos.length} videos \u2014 ${lf} long form, ${sh} shorts \u2014 ${gotT} transcripts \u00b7 Cached ${cacheDate}`;\n    return true;\n  } catch(e) { return false; }\n}\n\nwindow.addEventListener('DOMContentLoaded', () => {\n  initOAuth();\n});\n\n// \u2500\u2500\u2500 NAV \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction showPage(id) {\n  document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));\n  document.querySelectorAll('.nav-tab').forEach(t => t.classList.remove('active'));\n  document.getElementById('page-' + id).classList.add('active');\n  // Find and activate the matching nav tab\n  document.querySelectorAll('.nav-tab').forEach(t => {\n    if (t.getAttribute('onclick')?.includes(`'${id}'`)) t.classList.add('active');\n  });\n}\n\n// \u2500\u2500\u2500 FILE UPLOAD \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function handleFileUpload(e) {\n  const file = e.target.files[0];\n  if (!file) return;\n\n  document.getElementById('uploadProgress').style.display = 'block';\n  setProgress(10, 'Reading file...');\n\n  try {\n    let csvText = '';\n\n    if (file.name.endsWith('.zip')) {\n      // Use JSZip loaded from CDN\n      const script = document.createElement('script');\n      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';\n      document.head.appendChild(script);\n      await new Promise(r => script.onload = r);\n\n      const arrayBuffer = await file.arrayBuffer();\n      const zip = await JSZip.loadAsync(arrayBuffer);\n      const tableFile = Object.keys(zip.files).find(n => n.includes('Table data'));\n      if (!tableFile) throw new Error('Could not find \"Table data.csv\" in the ZIP');\n      csvText = await zip.files[tableFile].async('text');\n    } else {\n      csvText = await file.text();\n    }\n\n    setProgress(30, 'Parsing CSV...');\n    const videos = parseCSV(csvText);\n    setProgress(50, `Found ${videos.length} videos. Fetching transcripts...`);\n\n    // Fetch transcripts for top 10 longs (by views)\n    const longs = videos.filter(v => v.duration > 60).sort((a,b) => b.views - a.views).slice(0, 10);\n    let fetched = 0;\n\n    // Show transcript status panel \u2014 render all rows first as \"queued\"\n    document.getElementById('transcriptStatus').style.display = 'block';\n    const transcriptRows = document.getElementById('transcriptRows');\n    transcriptRows.innerHTML = '';\n    const transcriptResults = [];\n\n    for (const vid of longs) {\n      const row = document.createElement('div');\n      row.style.cssText = 'padding:8px 0;border-bottom:1px solid var(--border);';\n      row.innerHTML = `\n        <div style=\"display:flex;align-items:center;gap:10px;margin-bottom:4px\">\n          <div style=\"width:8px;height:8px;border-radius:50%;background:var(--border2);flex-shrink:0;transition:all 0.3s\" id=\"tdot-${vid.id}\"></div>\n          <div style=\"flex:1;font-size:12px;color:var(--muted2);white-space:nowrap;overflow:hidden;text-overflow:ellipsis\">${vid.title.slice(0,60)}${vid.title.length>60?'...':''}</div>\n          <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:10px;letter-spacing:0.1em;text-transform:uppercase;flex-shrink:0;transition:color 0.3s;color:var(--muted)\" id=\"tstatus-${vid.id}\">Queued</div>\n        </div>\n        <div style=\"height:2px;background:var(--border);border-radius:1px;overflow:hidden\">\n          <div id=\"tbar-${vid.id}\" style=\"height:100%;width:0%;background:var(--accent);border-radius:1px;transition:width 0.4s ease\"></div>\n        </div>`;\n      transcriptRows.appendChild(row);\n    }\n\n    for (const vid of longs) {\n      // Wait between requests to avoid Supadata rate limit (BEFORE fetch)\n      if (fetched > 0) {\n        document.getElementById('tstatus-' + vid.id).textContent = 'Waiting...';\n        await new Promise(r => setTimeout(r, 4000));\n      }\n\n      // Animate to \"fetching\" state\n      document.getElementById('tdot-' + vid.id).style.background = 'var(--accent)';\n      document.getElementById('tdot-' + vid.id).style.boxShadow = '0 0 6px var(--accent)';\n      document.getElementById('tstatus-' + vid.id).style.color = 'var(--accent)';\n      document.getElementById('tstatus-' + vid.id).textContent = 'Fetching...';\n      document.getElementById('tbar-' + vid.id).style.width = '60%';\n\n      try {\n        // Retry once on 429\n        let transcript;\n        try {\n          transcript = await fetchTranscript(vid.id);\n        } catch(retryErr) {\n          if (retryErr.message && retryErr.message.includes('429')) {\n            await new Promise(r => setTimeout(r, 5000));\n            transcript = await fetchTranscript(vid.id);\n          } else {\n            throw retryErr;\n          }\n        }\n        vid.transcript = transcript;\n        document.getElementById('tbar-' + vid.id).style.width = '100%';\n        document.getElementById('tbar-' + vid.id).style.background = 'var(--green)';\n        document.getElementById('tdot-' + vid.id).style.background = 'var(--green)';\n        document.getElementById('tdot-' + vid.id).style.boxShadow = '0 0 6px var(--green)';\n        document.getElementById('tstatus-' + vid.id).style.color = 'var(--green)';\n        document.getElementById('tstatus-' + vid.id).textContent = `\u2713 ~${Math.round(transcript.split(' ').length)} words`;\n        transcriptResults.push({ ok: true });\n      } catch(err) {\n        // Failure \u2014 show actual error\n        document.getElementById('tbar-' + vid.id).style.width = '100%';\n        document.getElementById('tbar-' + vid.id).style.background = 'var(--accent2)';\n        document.getElementById('tdot-' + vid.id).style.background = 'var(--accent2)';\n        document.getElementById('tdot-' + vid.id).style.boxShadow = 'none';\n        document.getElementById('tstatus-' + vid.id).style.color = 'var(--accent2)';\n        document.getElementById('tstatus-' + vid.id).textContent = '\u2717 ' + (err.message || 'Failed');\n        transcriptResults.push({ ok: false });\n      }\n      fetched++;\n      setProgress(50 + Math.round((fetched / longs.length) * 30), `Transcripts: ${fetched}/${longs.length}`);\n    }\n\n    const gotTranscripts = transcriptResults.filter(r => r.ok).length;\n    const hasKey = document.getElementById('supadataKey').value.trim().length > 0;\n    document.getElementById('transcriptSummary').textContent =\n      gotTranscripts > 0\n        ? `${gotTranscripts} of ${longs.length} transcripts retrieved \u2014 channel DNA analysis is now script-aware`\n        : hasKey\n          ? `No transcripts retrieved \u2014 Supadata key may be invalid or quota reached. Analysis uses titles + performance data.`\n          : `No transcripts retrieved \u2014 add a free Supadata API key above and re-upload to enable script analysis.`;\n    document.getElementById('transcriptSummary').style.color = gotTranscripts > 0 ? 'var(--green)' : hasKey ? 'var(--accent2)' : 'var(--muted2)';\n\n    setProgress(85, 'Analysing channel patterns...');\n    channelData = videos;\n    const dna = await buildChannelDNA(videos);\n    channelDNA = dna;\n\n    setProgress(100, 'Done!');\n    renderInsights(videos);\n    renderDNA(dna);\n    updateStatus(videos.length);\n\n    document.getElementById('uploadProgress').style.display = 'none';\n    document.getElementById('uploadSuccess').style.display = 'block';\n    const lf = videos.filter(v => v.duration > 60).length;\n    const sh = videos.filter(v => v.duration <= 60).length;\n    document.getElementById('uploadSummary').textContent = `${videos.length} videos loaded \u2014 ${lf} long form, ${sh} shorts \u2014 ${gotTranscripts} transcripts`;\n\n  } catch(err) {\n    setProgress(0, 'Error: ' + err.message);\n    console.error(err);\n  }\n}\n\nfunction setProgress(pct, label) {\n  document.getElementById('progressFill').style.width = pct + '%';\n  document.getElementById('progressLabel').textContent = label;\n  document.getElementById('progressPct').textContent = pct + '%';\n}\n\n// \u2500\u2500\u2500 CSV PARSER \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction parseCSV(text) {\n  const lines = text.split('\\n').filter(l => l.trim());\n  const headers = parseCSVLine(lines[0]);\n  const videos = [];\n\n  for (let i = 1; i < lines.length; i++) {\n    const cols = parseCSVLine(lines[i]);\n    if (!cols[0] || cols[0] === 'Total') continue;\n    const row = {};\n    headers.forEach((h, idx) => row[h.trim()] = (cols[idx] || '').trim());\n    const dur = parseInt(row['Duration']) || 0;\n    if (!dur) continue;\n    videos.push({\n      id: row['Content'],\n      title: row['Video title'],\n      published: row['Video publish time'],\n      duration: dur,\n      views: parseInt(row['Views']) || 0,\n      impressions: parseInt(row['Impressions']) || 0,\n      ctr: parseFloat(row['Impressions click-through rate (%)']) || 0,\n      avgViewDuration: row['Average view duration'],\n      avgPctViewed: parseFloat(row['Average percentage viewed (%)']) || 0,\n      watchHours: parseFloat(row['Watch time (hours)']) || 0,\n      subscribers: parseInt(row['Subscribers']) || 0,\n      revenue: parseFloat(row['Estimated revenue (AUD)']) || 0,\n      isShort: dur <= 60,\n      transcript: null\n    });\n  }\n  return videos;\n}\n\nfunction parseCSVLine(line) {\n  const result = [];\n  let current = '';\n  let inQuotes = false;\n  for (let i = 0; i < line.length; i++) {\n    if (line[i] === '\"') { inQuotes = !inQuotes; }\n    else if (line[i] === ',' && !inQuotes) { result.push(current); current = ''; }\n    else { current += line[i]; }\n  }\n  result.push(current);\n  return result;\n}\n\n\n// \u2500\u2500\u2500 STATE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n// \u2500\u2500\u2500 TRANSCRIPT FETCHER \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function fetchTranscript(videoId) {\n  // Routes through our backend proxy \u2014 no CORS issues, API key stays server-side\n  const res = await fetch(`/api/transcript?videoId=${videoId}`);\n  if (!res.ok) {\n    const err = await res.json().catch(() => ({}));\n    throw new Error(`${res.status}: ${err.message || err.error || 'request failed'}`);\n  }\n  const data = await res.json();\n  let text = '';\n  if (typeof data.content === 'string') {\n    text = data.content;\n  } else if (Array.isArray(data.content)) {\n    text = data.content.map(s => s.text || '').join(' ');\n  }\n  if (!text || text.length < 30) throw new Error('No captions available');\n  return text.trim();\n}\n\n// \u2500\u2500\u2500 CHANNEL DNA BUILDER \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function buildChannelDNA(videos, thumbnailAnalysis = null) {\n  const longs = videos.filter(v => !v.isShort).sort((a,b) => b.views - a.views);\n  const shorts = videos.filter(v => v.isShort).sort((a,b) => b.views - a.views);\n  \n  const top5 = longs.slice(0, 5);\n  const bottom5 = longs.slice(-5).filter(v => v.views < 5000);\n  const topShorts = shorts.slice(0, 5);\n\n  const avgCTR = longs.reduce((s,v) => s + v.ctr, 0) / longs.length;\n  const avgViews = longs.reduce((s,v) => s + v.views, 0) / longs.length;\n\n  // Build DNA prompt\n  const dnaPrompt = `You are analysing a YouTube channel to extract a \"Channel DNA\" \u2014 a set of specific, actionable patterns about what makes content succeed or fail on this channel.\n\nChannel: Formula Zac \u2014 grassroots motorsport creator. Races a Hyper Racer X1 formula car in the Australian Drivers Championship. Also covers sim racing (iRacing). Small operation, genuine underdog.\n\nPERFORMANCE DATA:\nAverage long-form views: ${Math.round(avgViews).toLocaleString()}\nAverage CTR: ${avgCTR.toFixed(1)}%\n\nTOP PERFORMING LONG FORM (by views):\n${top5.map(v => `- \"${v.title}\" \u2014 ${v.views.toLocaleString()} views, ${v.ctr}% CTR${v.transcript ? `, transcript available` : ''}`).join('\\n')}\n\nUNDERPERFORMING LONG FORM:\n${bottom5.map(v => `- \"${v.title}\" \u2014 ${v.views.toLocaleString()} views, ${v.ctr}% CTR`).join('\\n')}\n\nTOP SHORTS:\n${topShorts.map(v => `- \"${v.title}\" \u2014 ${v.views.toLocaleString()} views, ${v.ctr}% CTR`).join('\\n')}\n\n${top5.some(v => v.transcript) ? `TRANSCRIPTS FROM TOP VIDEOS:\\n${top5.filter(v => v.transcript).map(v => `\"${v.title}\":\\n${v.transcript?.slice(0, 600)}...`).join('\\n\\n')}` : ''}\n\n${top5.some(v => v.comments?.length) ? `TOP COMMENTS FROM BEST VIDEOS:\\n${top5.filter(v => v.comments?.length).map(v => `\"${v.title}\":\\n${v.comments.slice(0,10).map(c => `- ${c.text.slice(0,120)}`).join('\\n')}`).join('\\n\\n')}` : ''}\n\n${thumbnailAnalysis ? `THUMBNAIL VISUAL ANALYSIS (from AI vision):\nWhat works visually: ${thumbnailAnalysis.whatWorks?.join(' | ')}\nWhat doesn't work: ${thumbnailAnalysis.whatDoesntWork?.join(' | ')}\nFace/expression insight: ${thumbnailAnalysis.faceInsight}\nText overlay insight: ${thumbnailAnalysis.textInsight}\nComposition insight: ${thumbnailAnalysis.compositionInsight}\nBest thumbnail: ${thumbnailAnalysis.topThumbnail}` : ''}\n\nExtract the Channel DNA as a JSON object with these exact keys:\n{\n  \"whatWorks\": [\"3-5 specific patterns that correlate with high performance \u2014 be specific, not generic\"],\n  \"whatFails\": [\"3-4 specific patterns from underperforming content\"],\n  \"titlePatterns\": [\"2-3 title structures that work for this channel\"],\n  \"thumbnailPatterns\": [\"2-3 thumbnail approaches that work\"],\n  \"shortPatterns\": [\"2-3 patterns from top shorts\"],\n  \"audienceTriggers\": [\"3-4 emotions or situations that resonate with this specific audience\"],\n  \"avoidList\": [\"3-4 specific things to avoid based on the data\"],\n      \"thumbnailInsights\": \"one sentence on key visual thumbnail pattern from the data \u2014 only if thumbnail analysis was provided, otherwise empty string\"\n}\n\nReturn ONLY valid JSON. No markdown, no explanation.`;\n\n  try {\n    const res = await fetch('/api/claude', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        model: 'claude-sonnet-4-20250514',\n        max_tokens: 2000,\n        messages: [{ role: 'user', content: dnaPrompt }]\n      })\n    });\n    const data = await res.json();\n    const text = data.content?.map(i => i.text || '').join('') || '';\n    const clean = text.replace(/```json|```/g, '').trim();\n    return JSON.parse(clean);\n  } catch(e) {\n    // Fallback DNA based on the known data\n    return {\n      whatWorks: [\n        \"Stranger-accessible conflict \u2014 viewer understands the stakes without knowing the creator\",\n        \"Underdog framing ('basically no money', 'shouldn't be here')\",\n        \"Specific numbers on screen as proof (iRating +512, costs, lap times)\",\n        \"iRacing utility content \u2014 high search intent from sim racing audience\",\n        \"Build series content \u2014 curiosity gap sustained across episodes\"\n      ],\n      whatFails: [\n        \"Creator-centric framing that requires prior relationship to care ('Can We Save It?')\",\n        \"Generic race recap without a stranger-accessible hook\",\n        \"Pure onboard footage without narrative context\",\n        \"Titles that describe rather than create intrigue\"\n      ],\n      titlePatterns: [\n        \"'I [did something unexpected/extreme] + [context]'\",\n        \"'The Truth About [specific topic]...'\",\n        \"'This [thing] [bold claim]'\"\n      ],\n      thumbnailPatterns: [\n        \"Strong expressive face + uncomfortable text that creates conflict\",\n        \"Green arrow pointing at something surprising\",\n        \"Stats/numbers overlaid as visual proof\"\n      ],\n      shortPatterns: [\n        \"Pure spectacle moments \u2014 sound, crashes, saves \u2014 no setup needed\",\n        \"Curiosity gap ('NO PRACTICE QUALIFYING', 'HUGE DISASTER')\",\n        \"High CTR when content is universally understandable to any motorsport viewer\"\n      ],\n      audienceTriggers: [\n        \"Relatability of doing motorsport on a budget\",\n        \"The gap between sim racing and real racing\",\n        \"Underdog vs established competition\",\n        \"Technical curiosity about formula car engineering\"\n      ],\n      avoidList: [\n        \"Titles/thumbnails requiring prior context to feel the stakes\",\n        \"Generic 'EPIC' or 'INSANE' titles without specificity\",\n        \"Race recaps without a strong narrative frame\",\n        \"Workshop content without a clear tension or goal\"\n      ]\n    };\n  }\n}\n\n// \u2500\u2500\u2500 RENDER DNA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction renderDNA(dna) {\n  if (!dna) return;\n  const el = document.getElementById('dnaContent');\n  const section = (title, items, color) => `\n    <div style=\"margin-bottom:14px\">\n      <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:10px;font-weight:700;letter-spacing:0.15em;text-transform:uppercase;color:${color};margin-bottom:6px\">${title}</div>\n      ${items.map(i => `<div style=\"display:flex;gap:7px;align-items:flex-start;margin-bottom:5px\"><div style=\"width:4px;height:4px;border-radius:50%;background:${color};margin-top:5px;flex-shrink:0\"></div><span>${i}</span></div>`).join('')}\n    </div>`;\n\n  el.innerHTML =\n    section('What Works', dna.whatWorks, 'var(--green)') +\n    section('What Fails', dna.whatFails, 'var(--accent2)') +\n    section('Title Patterns', dna.titlePatterns, 'var(--accent)') +\n    section('Thumbnail Patterns', dna.thumbnailPatterns, 'var(--blue)') +\n    section('Shorts Patterns', dna.shortPatterns, 'var(--blue)') +\n    section('Audience Triggers', dna.audienceTriggers, 'var(--accent)') +\n    section('Avoid', dna.avoidList, 'var(--accent2)');\n}\n\n// \u2500\u2500\u2500 RENDER INSIGHTS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction renderInsights(videos, thumbnailAnalysis = null) {\n  document.getElementById('insightsEmpty').style.display = 'none';\n  document.getElementById('insightsContent').style.display = 'block';\n\n  // Render thumbnail analysis if available\n  if (thumbnailAnalysis) {\n    document.getElementById('thumbnailInsightsEmpty').style.display = 'none';\n    document.getElementById('thumbnailInsightsContent').style.display = 'block';\n    renderThumbnailInsights(thumbnailAnalysis);\n  } else {\n    document.getElementById('thumbnailInsightsEmpty').style.display = 'block';\n    document.getElementById('thumbnailInsightsContent').style.display = 'none';\n  }\n\n  const longs = videos.filter(v => !v.isShort);\n  const shorts = videos.filter(v => v.isShort);\n  const totalViews = videos.reduce((s,v) => s + v.views, 0);\n  const avgCTR = (longs.reduce((s,v) => s + v.ctr, 0) / longs.length).toFixed(1);\n  const topVideo = [...videos].sort((a,b) => b.views - a.views)[0];\n\n  // Separate stats\n  const longViews = longs.reduce((s,v) => s + v.views, 0);\n  const shortViews = shorts.reduce((s,v) => s + v.views, 0);\n  const avgLongCTR = longs.length ? (longs.reduce((s,v) => s + v.ctr, 0) / longs.length).toFixed(1) : '\u2014';\n  const avgShortCTR = shorts.length ? (shorts.filter(v => v.ctr > 0).reduce((s,v) => s + v.ctr, 0) / (shorts.filter(v => v.ctr > 0).length || 1)).toFixed(1) : '\u2014';\n  const avgLongRetention = longs.length ? Math.round(longs.filter(v => v.avgPctViewed > 0).reduce((s,v) => s + v.avgPctViewed, 0) / (longs.filter(v => v.avgPctViewed > 0).length || 1)) : '\u2014';\n  const topLong = [...longs].sort((a,b) => b.views - a.views)[0];\n  const topShort = [...shorts].sort((a,b) => b.views - a.views)[0];\n\n  document.getElementById('statsGrid').innerHTML = `\n    <div class=\"stat-card\" style=\"border-top:2px solid var(--accent)\">\n      <div class=\"card-label\" style=\"color:var(--accent);margin-bottom:6px\">Long Form</div>\n      <div class=\"stat-value\">${(longViews/1000).toFixed(0)}K</div>\n      <div class=\"stat-label\">Total Views \u00b7 ${longs.length} videos</div>\n    </div>\n    <div class=\"stat-card\" style=\"border-top:2px solid var(--accent)\">\n      <div class=\"card-label\" style=\"color:var(--accent);margin-bottom:6px\">Long Form CTR</div>\n      <div class=\"stat-value\">${avgLongCTR}%</div>\n      <div class=\"stat-label\">Avg across all long form</div>\n    </div>\n    <div class=\"stat-card\" style=\"border-top:2px solid var(--accent)\">\n      <div class=\"card-label\" style=\"color:var(--accent);margin-bottom:6px\">Avg Retention</div>\n      <div class=\"stat-value\">${avgLongRetention}%</div>\n      <div class=\"stat-label\">Long form average</div>\n    </div>\n    <div class=\"stat-card\" style=\"border-top:2px solid var(--blue)\">\n      <div class=\"card-label\" style=\"color:var(--blue);margin-bottom:6px\">Shorts</div>\n      <div class=\"stat-value\">${(shortViews/1000).toFixed(0)}K</div>\n      <div class=\"stat-label\">Total Views \u00b7 ${shorts.length} videos</div>\n    </div>\n    <div class=\"stat-card\" style=\"border-top:2px solid var(--blue)\">\n      <div class=\"card-label\" style=\"color:var(--blue);margin-bottom:6px\">Best Long Form</div>\n      <div class=\"stat-value\" style=\"font-size:18px;line-height:1.2\">${topLong ? (topLong.views/1000).toFixed(0)+'K' : '\u2014'}</div>\n      <div class=\"stat-label\" style=\"white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:160px\">${topLong?.title?.slice(0,30) || ''}...</div>\n    </div>\n    <div class=\"stat-card\" style=\"border-top:2px solid var(--blue)\">\n      <div class=\"card-label\" style=\"color:var(--blue);margin-bottom:6px\">Best Short</div>\n      <div class=\"stat-value\" style=\"font-size:18px;line-height:1.2\">${topShort ? (topShort.views/1000).toFixed(0)+'K' : '\u2014'}</div>\n      <div class=\"stat-label\" style=\"white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:160px\">${topShort?.title?.slice(0,30) || ''}...</div>\n    </div>\n  `;\n\n  // Insights \u2014 separated by format\n  const longsTop = [...longs].sort((a,b) => b.views - a.views).slice(0,4);\n  const avgLongViewsNum = Math.round(longViews / (longs.length || 1));\n  const longsWorst = [...longs].sort((a,b) => a.views - b.views).filter(v => v.views < avgLongViewsNum).slice(0,4);\n  const highCTRLongs = [...longs].filter(v => v.ctr > 0).sort((a,b) => b.ctr - a.ctr).slice(0,4);\n  const shortsTop = [...shorts].sort((a,b) => b.views - a.views).slice(0,4);\n\n  document.getElementById('insightsGrid').innerHTML = `\n    <div class=\"insight-card\">\n      <div class=\"insight-title\" style=\"color:var(--accent)\">Top Long Form</div>\n      <div style=\"font-size:10px;color:var(--muted);margin-bottom:8px;font-family:'Barlow Condensed',sans-serif;letter-spacing:0.1em;text-transform:uppercase\">Channel avg: ${(avgLongViewsNum/1000).toFixed(1)}K views</div>\n      ${longsTop.map(v => `<div class=\"insight-item\"><div class=\"insight-dot\"></div><div><strong style=\"color:var(--text)\">${(v.views/1000).toFixed(1)}K</strong> \u00b7 ${v.ctr}% CTR \u00b7 ${v.title.slice(0,45)}${v.title.length>45?'...':''}</div></div>`).join('')}\n    </div>\n    <div class=\"insight-card\">\n      <div class=\"insight-title\" style=\"color:var(--accent)\">Highest CTR \u2014 Long Form</div>\n      <div style=\"font-size:10px;color:var(--muted);margin-bottom:8px;font-family:'Barlow Condensed',sans-serif;letter-spacing:0.1em;text-transform:uppercase\">Channel avg: ${avgLongCTR}% CTR</div>\n      ${highCTRLongs.map(v => `<div class=\"insight-item\"><div class=\"insight-dot blue\"></div><div><strong style=\"color:var(--text)\">${v.ctr}% CTR</strong> \u00b7 ${(v.views/1000).toFixed(1)}K \u00b7 ${v.title.slice(0,45)}${v.title.length>45?'...':''}</div></div>`).join('')}\n    </div>\n    <div class=\"insight-card\">\n      <div class=\"insight-title\" style=\"color:var(--blue)\">Top Shorts</div>\n      <div style=\"font-size:10px;color:var(--muted);margin-bottom:8px;font-family:'Barlow Condensed',sans-serif;letter-spacing:0.1em;text-transform:uppercase\">${shorts.length} shorts total</div>\n      ${shortsTop.map(v => `<div class=\"insight-item\"><div class=\"insight-dot blue\"></div><div><strong style=\"color:var(--text)\">${(v.views/1000).toFixed(1)}K</strong> \u00b7 ${v.ctr > 0 ? v.ctr + '% CTR \u00b7 ' : ''}${v.title.slice(0,45)}${v.title.length>45?'...':''}</div></div>`).join('')}\n    </div>\n    <div class=\"insight-card\">\n      <div class=\"insight-title\" style=\"color:var(--accent2)\">Long Form Underperformers</div>\n      <div style=\"font-size:10px;color:var(--muted);margin-bottom:8px;font-family:'Barlow Condensed',sans-serif;letter-spacing:0.1em;text-transform:uppercase\">Below channel average</div>\n      ${longsWorst.map(v => `<div class=\"insight-item\"><div class=\"insight-dot red\"></div><div><strong style=\"color:var(--text)\">${(v.views/1000).toFixed(1)}K</strong> \u00b7 ${v.ctr}% CTR \u00b7 ${v.title.slice(0,45)}${v.title.length>45?'...':''}</div></div>`).join('')}\n    </div>\n  `;\n\n  // Tables\n  renderVideoTable('longsTable', [...longs].sort((a,b) => b.views - a.views));\n  renderVideoTable('shortsTable', [...shorts].sort((a,b) => b.views - a.views));\n\n  // Kick off AI strategy analysis\n  generateStrategyBrief(videos, thumbnailAnalysis);\n}\n\n// \u2500\u2500\u2500 THUMBNAIL INSIGHTS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction renderThumbnailInsights(t) {\n  const cards = document.getElementById('thumbnailCards');\n  cards.innerHTML = `\n    <div class=\"strategy-card\">\n      <div class=\"strategy-card-title\" style=\"color:var(--green)\">What Works Visually</div>\n      ${t.whatWorks?.map(i => `<div class=\"strategy-item\"><div class=\"strategy-dot\" style=\"background:var(--green)\"></div><div>${i}</div></div>`).join('') || ''}\n      ${t.faceInsight ? `<div style=\"margin-top:10px;padding-top:10px;border-top:1px solid var(--border);font-size:12px;color:var(--muted2)\"><strong style=\"color:var(--accent)\">Face/Expression:</strong> ${t.faceInsight}</div>` : ''}\n    </div>\n    <div class=\"strategy-card\">\n      <div class=\"strategy-card-title\" style=\"color:var(--accent2)\">What Doesn't Work</div>\n      ${t.whatDoesntWork?.map(i => `<div class=\"strategy-item\"><div class=\"strategy-dot\" style=\"background:var(--accent2)\"></div><div>${i}</div></div>`).join('') || ''}\n      ${t.textInsight ? `<div style=\"margin-top:10px;padding-top:10px;border-top:1px solid var(--border);font-size:12px;color:var(--muted2)\"><strong style=\"color:var(--accent)\">Text Overlays:</strong> ${t.textInsight}</div>` : ''}\n      ${t.compositionInsight ? `<div style=\"margin-top:8px;font-size:12px;color:var(--muted2)\"><strong style=\"color:var(--accent)\">Composition:</strong> ${t.compositionInsight}</div>` : ''}\n    </div>`;\n\n  document.getElementById('thumbnailRecommendation').innerHTML = `\n    <div class=\"card-label\" style=\"color:var(--accent);margin-bottom:8px\">Best Thumbnail on Your Channel</div>\n    <div style=\"font-size:13px;color:#ccc;line-height:1.6;margin-bottom:12px\">${t.topThumbnail || ''}</div>\n    <div class=\"card-label\" style=\"color:var(--blue);margin-bottom:8px\">Next Thumbnail Recommendation</div>\n    <div style=\"font-size:14px;color:var(--text);line-height:1.6\">${t.recommendation || ''}</div>`;\n}\n\n// \u2500\u2500\u2500 AI STRATEGY BRIEF \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function generateStrategyBrief(videos, thumbnailAnalysis = null) {\n  document.getElementById('strategyLoading').style.display = 'block';\n  document.getElementById('strategyContent').style.display = 'none';\n\n  const longs = videos.filter(v => !v.isShort).sort((a,b) => b.views - a.views);\n  const shorts = videos.filter(v => v.isShort).sort((a,b) => b.views - a.views);\n  const avgCTR = (longs.reduce((s,v) => s+v.ctr, 0) / longs.length).toFixed(1);\n  const avgViews = Math.round(longs.reduce((s,v) => s+v.views, 0) / longs.length);\n\n  const prompt = `You are a YouTube channel strategist analysing Formula Zac's channel data.\n\nChannel: Formula Zac \u2014 grassroots motorsport, Hyper Racer X1 formula car, Australian Drivers Championship + iRacing sim racing content.\n\nPERFORMANCE DATA:\nAverage long-form views: ${avgViews.toLocaleString()}\nAverage CTR: ${avgCTR}%\n\nTOP 8 LONG FORM (views | CTR | title):\n${longs.slice(0,8).map(v => `${v.views.toLocaleString()} views | ${v.ctr}% CTR | \"${v.title}\"`).join('\\n')}\n\nBOTTOM 5 LONG FORM:\n${longs.slice(-5).map(v => `${v.views.toLocaleString()} views | ${v.ctr}% CTR | \"${v.title}\"`).join('\\n')}\n\nTOP 5 SHORTS:\n${shorts.slice(0,5).map(v => `${v.views.toLocaleString()} views | ${v.ctr}% CTR | \"${v.title}\"`).join('\\n')}\n\n${thumbnailAnalysis ? `\nTHUMBNAIL VISUAL ANALYSIS:\nWorks: ${thumbnailAnalysis.whatWorks?.join(' | ')}\nDoesn't work: ${thumbnailAnalysis.whatDoesntWork?.join(' | ')}\nRecommendation: ${thumbnailAnalysis.recommendation}` : ''}\n\nAnalyse this data and return a JSON strategy brief. Be specific \u2014 reference actual video titles, thumbnail patterns, and comment sentiment. No generic advice.\n\nReturn ONLY valid JSON:\n{\n  \"doMore\": [\"4-5 specific content types or patterns proven to work \u2014 cite actual titles as evidence\"],\n  \"stopDoing\": [\"3-4 specific things proven not to work \u2014 cite actual titles\"],\n  \"quickWins\": [\"3 specific actionable things to do in the next 30 days based on the data\"],\n  \"bigOpportunity\": \"One paragraph \u2014 the single biggest untapped opportunity this channel has based on what's working\",\n  \"ctrInsight\": \"One specific observation about CTR patterns across the top vs bottom performers\",\n  \"shortsStrategy\": \"One specific insight about what makes shorts work on this channel\"\n}`;\n\n  try {\n    const res = await fetch('/api/claude', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        model: 'claude-sonnet-4-20250514',\n        max_tokens: 2000,\n        messages: [{ role: 'user', content: prompt }]\n      })\n    });\n\n    const data = await res.json();\n    const text = data.content?.map(i => i.text || '').join('') || '';\n    const clean = text.replace(/```json|```/g, '').trim();\n    const strategy = JSON.parse(clean);\n\n    renderStrategyBrief(strategy);\n  } catch(err) {\n    document.getElementById('strategyLoading').style.display = 'none';\n    console.error('Strategy brief failed:', err);\n  }\n}\n\nfunction renderStrategyBrief(s) {\n  document.getElementById('strategyLoading').style.display = 'none';\n  document.getElementById('strategyContent').style.display = 'block';\n\n  const cards = document.getElementById('strategyCards');\n  cards.innerHTML = `\n    <div class=\"strategy-card\">\n      <div class=\"strategy-card-title\" style=\"color:var(--green)\">Do More Of This</div>\n      ${s.doMore.map(i => `<div class=\"strategy-item\"><div class=\"strategy-dot\" style=\"background:var(--green)\"></div><div>${i}</div></div>`).join('')}\n    </div>\n    <div class=\"strategy-card\">\n      <div class=\"strategy-card-title\" style=\"color:var(--accent2)\">Stop / Avoid</div>\n      ${s.stopDoing.map(i => `<div class=\"strategy-item\"><div class=\"strategy-dot\" style=\"background:var(--accent2)\"></div><div>${i}</div></div>`).join('')}\n    </div>\n    <div class=\"strategy-card\">\n      <div class=\"strategy-card-title\" style=\"color:var(--accent)\">Quick Wins \u2014 Next 30 Days</div>\n      ${s.quickWins.map(i => `<div class=\"strategy-item\"><div class=\"strategy-dot\" style=\"background:var(--accent)\"></div><div>${i}</div></div>`).join('')}\n    </div>\n    <div class=\"strategy-card\">\n      <div class=\"strategy-card-title\" style=\"color:var(--blue)\">CTR Insight</div>\n      <div style=\"font-size:13px;line-height:1.6;color:#ccc\">${s.ctrInsight}</div>\n      <div style=\"margin-top:12px;padding-top:12px;border-top:1px solid var(--border)\">\n        <div class=\"strategy-card-title\" style=\"color:var(--blue);margin-bottom:8px\">Shorts Strategy</div>\n        <div style=\"font-size:13px;line-height:1.6;color:#ccc\">${s.shortsStrategy}</div>\n      </div>\n    </div>\n  `;\n\n  document.getElementById('strategyDeep').innerHTML = `\n    <div class=\"card-label\" style=\"color:var(--accent);margin-bottom:10px\">Biggest Opportunity</div>\n    <div style=\"font-size:14px;line-height:1.8;color:#ccc\">${s.bigOpportunity}</div>\n  `;\n}\n\nfunction renderVideoTable(tableId, videos) {\n  const maxViews = Math.max(...videos.map(v => v.views));\n  const table = document.getElementById(tableId);\n  table.innerHTML = `\n    <thead><tr>\n      <th>Title</th>\n      <th>Views</th>\n      <th>CTR</th>\n      <th>Avg View %</th>\n      <th>Published</th>\n    </tr></thead>\n    <tbody>\n      ${videos.map(v => `<tr>\n        <td style=\"max-width:300px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis\">${v.title}</td>\n        <td style=\"white-space:nowrap\">\n          ${v.views.toLocaleString()}\n          <span class=\"perf-bar\" style=\"width:${Math.round((v.views/maxViews)*60)}px\"></span>\n        </td>\n        <td>${v.ctr}%</td>\n        <td>${v.avgPctViewed}%</td>\n        <td style=\"color:var(--muted2);white-space:nowrap\">${v.published}</td>\n      </tr>`).join('')}\n    </tbody>`;\n}\n\nfunction updateStatus(count) {\n  document.getElementById('statusDot').classList.add('ready');\n  document.getElementById('statusText').textContent = `${count} videos loaded`;\n}\n\n// \u2500\u2500\u2500 FORMAT SELECTOR \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlet selectedFormat = 'long';\nlet conceptStore = []; // stores concepts so buttons can reference by index\nfunction selectFormat(fmt) {\n  selectedFormat = fmt;\n  document.getElementById('fmtLong').classList.toggle('active', fmt === 'long');\n  document.getElementById('fmtShort').classList.toggle('active', fmt === 'short');\n}\n\n// \u2500\u2500\u2500 SCRIPT STATE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlet currentScript = '';\nlet currentConcept = null;\nlet chatMessages = [];\n\n// \u2500\u2500\u2500 GENERATE CONCEPTS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function generateConcepts(extraInstruction = '') {\n  const notes = document.getElementById('notesInput').value.trim();\n  if (notes.length < 30) {\n    showError('Give me more detail \u2014 at least a few sentences about what actually happened.');\n    return;\n  }\n\n  document.getElementById('genBtn').disabled = true;\n  document.getElementById('genError').classList.remove('show');\n  document.getElementById('genLoading').classList.add('show');\n  document.getElementById('conceptsOutput').innerHTML = '';\n  document.getElementById('scriptPanel').style.display = 'none';\n\n  const loadingMsgs = ['Analysing your story...', 'Checking channel patterns...', 'Building concepts...', 'Writing angles...'];\n  let msgIdx = 0;\n  const msgInterval = setInterval(() => {\n    msgIdx = (msgIdx + 1) % loadingMsgs.length;\n    document.getElementById('loadingMsg').textContent = loadingMsgs[msgIdx];\n  }, 1800);\n\n  try {\n    const res = await fetch('/api/claude', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        model: 'claude-sonnet-4-20250514',\n        max_tokens: 4000,\n        system: buildConceptsPrompt(extraInstruction),\n        messages: [{ role: 'user', content: `Format: ${selectedFormat}\\n\\nEvent notes:\\n\\n${notes}` }]\n      })\n    });\n\n    const data = await res.json();\n    const text = data.content?.map(i => i.text || '').join('') || '';\n    const clean = text.replace(/```json|```/g, '').trim();\n    const parsed = JSON.parse(clean);\n\n    clearInterval(msgInterval);\n    document.getElementById('genLoading').classList.remove('show');\n    document.getElementById('genBtn').disabled = false;\n    renderConcepts(parsed.concepts);\n  } catch(err) {\n    clearInterval(msgInterval);\n    document.getElementById('genLoading').classList.remove('show');\n    document.getElementById('genBtn').disabled = false;\n    showError('Generation failed: ' + (err.message || err.toString()));\n    console.error(err);\n  }\n}\n\n// \u2500\u2500\u2500 GENERATE FULL SCRIPT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function generateScript(concept, notes) {\n  currentConcept = concept;\n  chatMessages = [];\n\n  document.getElementById('scriptPanel').style.display = 'block';\n  document.getElementById('scriptPanelTitle').textContent = concept.title;\n  document.getElementById('scriptContent').textContent = 'Writing script...';\n  document.getElementById('chatHistory').innerHTML = '';\n  document.getElementById('scriptPanel').scrollIntoView({ behavior: 'smooth', block: 'start' });\n\n  try {\n    const res = await fetch('/api/claude', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        model: 'claude-sonnet-4-20250514',\n        max_tokens: 4000,\n        system: buildScriptPrompt(concept),\n        messages: [{ role: 'user', content: `Write the full ${selectedFormat === 'short' ? 'Short (under 60 seconds)' : 'long form'} script for this concept.\\n\\nTitle: \"${concept.title}\"\\nHook: ${concept.hook}\\n\\nOriginal notes: ${notes}` }]\n      })\n    });\n\n    const data = await res.json();\n    const script = data.content?.map(i => i.text || '').join('') || '';\n    currentScript = script;\n    document.getElementById('scriptContent').textContent = script;\n\n    // Seed chat history\n    chatMessages = [\n      { role: 'user', content: `Write the full script for: \"${concept.title}\"` },\n      { role: 'assistant', content: script }\n    ];\n  } catch(err) {\n    document.getElementById('scriptContent').textContent = 'Failed to generate script: ' + err.message;\n  }\n}\n\n// \u2500\u2500\u2500 REFINE SCRIPT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function refineScript() {\n  const input = document.getElementById('refineInput');\n  const feedback = input.value.trim();\n  if (!feedback) return;\n\n  const btn = document.getElementById('refineBtn');\n  btn.disabled = true;\n  input.value = '';\n\n  // Add user message to chat\n  const chatHistory = document.getElementById('chatHistory');\n  const userMsg = document.createElement('div');\n  userMsg.className = 'chat-msg';\n  userMsg.innerHTML = `<div class=\"chat-msg-user\">${feedback}</div>`;\n  chatHistory.appendChild(userMsg);\n\n  const aiMsg = document.createElement('div');\n  aiMsg.className = 'chat-msg chat-msg-ai';\n  aiMsg.textContent = 'Rewriting...';\n  chatHistory.appendChild(aiMsg);\n  chatHistory.scrollTop = chatHistory.scrollHeight;\n\n  chatMessages.push({ role: 'user', content: feedback });\n\n  try {\n    const res = await fetch('/api/claude', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        model: 'claude-sonnet-4-20250514',\n        max_tokens: 4000,\n        system: buildScriptPrompt(currentConcept),\n        messages: chatMessages\n      })\n    });\n\n    const data = await res.json();\n    const newScript = data.content?.map(i => i.text || '').join('') || '';\n    currentScript = newScript;\n\n    // Update the script display\n    document.getElementById('scriptContent').textContent = newScript;\n    chatMessages.push({ role: 'assistant', content: newScript });\n\n    aiMsg.textContent = '\u2713 Script updated above';\n    btn.disabled = false;\n    chatHistory.scrollTop = chatHistory.scrollHeight;\n    document.getElementById('scriptContent').scrollIntoView({ behavior: 'smooth', block: 'start' });\n  } catch(err) {\n    aiMsg.textContent = 'Error: ' + err.message;\n    btn.disabled = false;\n  }\n}\n\nfunction resetGenerate() {\n  document.getElementById('scriptPanel').style.display = 'none';\n  document.getElementById('conceptsOutput').innerHTML = '';\n  document.getElementById('notesInput').value = '';\n  document.getElementById('genInputSection').scrollIntoView({ behavior: 'smooth' });\n  currentScript = '';\n  currentConcept = null;\n  chatMessages = [];\n}\n\n// \u2500\u2500\u2500 SYSTEM PROMPTS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction buildConceptsPrompt(extraInstruction = '') {\n  const isShort = selectedFormat === 'short';\n  const dna = channelDNA ? `\nCHANNEL DNA (from real performance data):\nWhat works: ${channelDNA.whatWorks?.join(' | ')}\nWhat fails: ${channelDNA.whatFails?.join(' | ')}\nTitle patterns: ${channelDNA.titlePatterns?.join(' | ')}\nThumbnail patterns: ${channelDNA.thumbnailPatterns?.join(' | ')}\nShorts patterns: ${channelDNA.shortPatterns?.join(' | ')}\nAudience triggers: ${channelDNA.audienceTriggers?.join(' | ')}\nAvoid: ${channelDNA.avoidList?.join(' | ')}\n${channelDNA.thumbnailInsights ? `Thumbnail visual patterns (from AI vision): ${channelDNA.thumbnailInsights}` : ''}\n` : `\nKNOWN CHANNEL PATTERNS:\n- Stranger-accessible conflict works best\n- Underdog framing outperforms competence framing  \n- Specific numbers on screen boost CTR\n- \"I Should Not Be Here\" style titles outperform generic race recaps\n- Shorts: pure spectacle moments, disaster/save/overtake, no setup needed\n`;\n\n  const longSchema = `{\n  \"concepts\": [\n    {\n      \"title\": \"punchy stranger-accessible title under 60 chars\",\n      \"hook\": \"one sentence why a complete stranger clicks this\",\n      \"type\": \"stranger|utility|conflict|underdog\",\n      \"thumbnail\": {\n        \"brief\": \"detailed description of what to shoot and what text goes on the thumbnail\",\n        \"heroShot\": \"specific frame to capture during the talking head session for the thumbnail\"\n      },\n      \"shots\": [\n        { \"type\": \"talking|broll|sim|event\", \"description\": \"exactly what to film or say\" }\n      ],\n      \"whyItWorks\": \"one sentence tying this to proven channel patterns\"\n    }\n  ]\n}`;\n\n  const shortSchema = `{\n  \"concepts\": [\n    {\n      \"title\": \"short title or caption \u2014 punchy, under 40 chars, can include hashtags\",\n      \"hook\": \"one sentence describing the scroll-stopping first frame\",\n      \"type\": \"stranger|conflict|underdog\",\n      \"thumbnail\": {\n        \"brief\": \"describe the cover frame \u2014 what the viewer sees before they tap\",\n        \"heroShot\": \"the exact moment to use as the cover frame\"\n      },\n      \"shots\": [\n        { \"type\": \"event|sim|broll\", \"description\": \"what the shot is and roughly how long\" }\n      ],\n      \"caption\": \"the full caption text including hook line and hashtags\",\n      \"payoff\": \"what the satisfying end moment is \u2014 what makes them watch to the end\",\n      \"whyItWorks\": \"one sentence on why this works as a Short based on channel data\"\n    }\n  ]\n}`;\n\n  return `You are a YouTube content strategist for Formula Zac \u2014 a grassroots motorsport creator racing a Hyper Racer X1 formula car in the Australian Drivers Championship, also covering iRacing sim racing. Small budget, genuine underdog story.\n${dna}\nFORMAT: ${isShort ? 'SHORTS (under 60 seconds)' : 'LONG FORM (5-20 minutes)'}\n\n${isShort ? `For SHORTS:\n- No talking head, no setup, straight into the action\n- Hook must land in the first 1-2 seconds visually\n- Think: crash, overtake, spin, dramatic moment, unexpected result, funny moment\n- Cover frame (thumbnail) is critical \u2014 it needs to make someone tap\n- Caption should have a strong first line + relevant hashtags` : `For LONG FORM:\n- Stranger-accessible \u2014 works for someone who has never seen the channel\n- Strong narrative arc: hook \u2192 context \u2192 story \u2192 lesson\n- Thumbnail + title must communicate the conflict without needing to know Zac`}\n\nGenerate up to 10 video concepts. Aim for 8-10. Each must be a completely different angle on the same event.\n${extraInstruction ? `\nADDITIONAL INSTRUCTION: ${extraInstruction}` : ''}\n\nReturn ONLY valid JSON, no markdown, no backticks:\n${isShort ? shortSchema : longSchema}`;\n}\n\n\nfunction buildScriptPrompt(concept) {\n  const isShort = selectedFormat === 'short';\n  const dna = channelDNA ? `Channel patterns that work: ${channelDNA.whatWorks?.join(', ')}` : '';\n\n  return `You are writing a YouTube script for Formula Zac \u2014 grassroots motorsport creator, Hyper Racer X1 formula car, Australian Drivers Championship, also covers iRacing. Genuine underdog, real budget constraints, raw and honest tone.\n${dna}\n\n${isShort ? `WRITING A SHORT (under 60 seconds):\n- Hook must land in first 1-2 seconds \u2014 visual or line that stops the scroll\n- No intro, no setup \u2014 straight into the moment\n- Build to a clear payoff\n- Write it as a shooting script: describe visuals + caption/voiceover text\n- Format: [VISUAL: description] then dialogue/caption on next line` : `WRITING A LONG FORM VIDEO SCRIPT:\n- Open with the hook \u2014 the most interesting moment or question, not \"hey guys welcome back\"\n- Structure: Hook \u2192 Context (stranger-accessible background) \u2192 Main story \u2192 Key lesson/moment \u2192 Outro CTA\n- Write full dialogue as Zac would say it \u2014 casual, honest, self-aware, occasionally self-deprecating\n- Include [B-ROLL: description] cues inline where relevant\n- Include [TALKING HEAD] markers for on-camera sections\n- Include [SIM FOOTAGE: description] for iRacing sections\n- Aim for 800-1200 words for a 8-12 minute video`}\n\nThe concept you're scripting:\nTitle: \"${concept?.title}\"\nHook: ${concept?.hook}\nWhy it works: ${concept?.whyItWorks}\n\nWrite the complete script. When the user gives feedback, rewrite the full script incorporating their changes \u2014 always return the complete updated script, not just the changed section.`;\n}\n\nfunction buildSystemPrompt() { return buildConceptsPrompt(); }\n\n// \u2500\u2500\u2500 RENDER CONCEPTS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction renderConcepts(concepts) {\n  const types = { stranger: 'tb-stranger', utility: 'tb-utility', conflict: 'tb-conflict', underdog: 'tb-underdog' };\n  const typeLabels = { stranger: 'Stranger-Ready', utility: 'Utility', conflict: 'Conflict', underdog: 'Underdog' };\n  const shotTypes = { talking: 'st-talking', broll: 'st-broll', sim: 'st-sim', event: 'st-event' };\n  const shotLabels = { talking: 'Talking Head', broll: 'B-Roll', sim: 'Sim / iRacing', event: 'Event Footage' };\n\n  conceptStore = concepts; // save for button callbacks\n  const isShort = selectedFormat === 'short';\n  const notes = document.getElementById('notesInput').value.trim();\n  const out = document.getElementById('conceptsOutput');\n  out.innerHTML = `\n    <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;gap:12px;flex-wrap:wrap\">\n      <div style=\"font-family:'Barlow Condensed',sans-serif;font-size:11px;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted)\">${concepts.length} ${isShort ? 'Short' : 'Long Form'} Concepts</div>\n      <button class=\"btn btn-secondary\" style=\"font-size:11px;padding:8px 16px\" onclick=\"generateConcepts('These concepts are not landing. Try completely different angles, framings and hooks. Avoid similar titles or structures to what was just generated.')\">\n        \u21bb None of these work \u2014 try again\n      </button>\n    </div>`;\n\n  concepts.forEach((c, i) => {\n    const div = document.createElement('div');\n    div.className = 'concept-card';\n    div.innerHTML = `\n      <div class=\"concept-header\" onclick=\"toggleConcept(${i})\">\n        <div class=\"cn\">${String(i+1).padStart(2,'0')}</div>\n        <div>\n          <div class=\"ct\">${c.title}</div>\n          <div class=\"ch\">${c.hook}</div>\n        </div>\n        <div style=\"display:flex;flex-direction:column;align-items:flex-end;gap:6px;flex-shrink:0\">\n          <span class=\"type-badge ${types[c.type] || 'tb-stranger'}\">${typeLabels[c.type] || c.type}</span>\n          <svg class=\"chev\" id=\"chev-${i}\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><polyline points=\"6 9 12 15 18 9\"/></svg>\n        </div>\n      </div>\n      <div class=\"concept-body\" id=\"cb-${i}\">\n        <div class=\"cb-section\">\n          <div class=\"cb-label\">Cover Frame / Thumbnail</div>\n          <div class=\"thumb-block\">\n            ${c.thumbnail?.brief || '<span style=\"color:var(--muted2)\">\u2014</span>'}\n            ${c.thumbnail?.heroShot ? `<div class=\"hero-shot\"><strong>Key shot:</strong> ${c.thumbnail.heroShot}</div>` : ''}\n          </div>\n        </div>\n        ${isShort && c.caption ? `\n        <div class=\"cb-section\">\n          <div class=\"cb-label\">Caption</div>\n          <div style=\"background:var(--surface3);border:1px solid var(--border);border-radius:2px;padding:12px 14px;font-size:13px;line-height:1.6;color:#ccc;white-space:pre-wrap\">${c.caption}</div>\n        </div>\n        <div class=\"cb-section\">\n          <div class=\"cb-label\">Payoff Moment</div>\n          <div class=\"why-works\">${c.payoff || ''}</div>\n        </div>` : ''}\n        <div class=\"cb-section\">\n          <div class=\"cb-label\">Why This Works</div>\n          <div class=\"why-works\">${c.whyItWorks || ''}</div>\n        </div>\n        <div class=\"cb-section\">\n          <div class=\"cb-label\">${isShort ? 'Shots' : 'Shot List'}</div>\n          <ul class=\"shot-list\">\n            ${(c.shots || []).map(s => `\n              <li class=\"shot-item\">\n                <span class=\"shot-tag ${shotTypes[s.type] || 'st-broll'}\">${shotLabels[s.type] || s.type}</span>\n                <span>${s.description}</span>\n              </li>`).join('')}\n          </ul>\n        </div>\n        <div style=\"display:flex;gap:8px;margin-top:8px\">\n          <button class=\"btn btn-secondary\" style=\"flex:1;justify-content:center;font-size:11px;padding:10px 8px\" onclick=\"moreLikeThis(${i})\">More like this</button>\n          <button class=\"btn btn-primary\" style=\"flex:2;justify-content:center\" onclick=\"generateScript(conceptStore[${i}], document.getElementById('notesInput').value)\">Write Full Script \u2192</button>\n        </div>\n      </div>`;\n    out.appendChild(div);\n  });\n}\n\nfunction toggleConcept(i) {\n  const body = document.getElementById('cb-' + i);\n  const chev = document.getElementById('chev-' + i);\n  body.classList.toggle('open');\n  chev.classList.toggle('open');\n}\n\nfunction moreLikeThis(i) {\n  const concept = conceptStore[i];\n  if (!concept) return;\n  generateConcepts(`Generate more concepts similar to this one: \"${concept.title}\". Same type (${concept.type}), similar framing and emotional hook. Different specific angles but in the same spirit.`);\n}\n\n\n// \u2500\u2500\u2500 RETENTION \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction populateRetentionSelector(videos) {\n  const select = document.getElementById('retentionVideoSelect');\n  if (!select) return;\n  const longs = videos.filter(v => !v.isShort).sort((a,b) => b.views - a.views);\n  select.innerHTML = '<option value=\"\">\u2014 Choose a video \u2014</option>';\n  longs.forEach(v => {\n    const opt = document.createElement('option');\n    opt.value = v.id;\n    opt.textContent = `${v.title.slice(0, 60)}${v.title.length > 60 ? '...' : ''} \u2014 ${v.views.toLocaleString()} views`;\n    select.appendChild(opt);\n  });\n  document.getElementById('retentionEmpty').style.display = 'none';\n  document.getElementById('retentionContent').style.display = 'block';\n}\n\nasync function loadRetentionForVideo(videoId) {\n  if (!videoId || !googleAccessToken) return;\n\n  const video = channelData?.find(v => v.id === videoId);\n  if (!video) return;\n\n  document.getElementById('retentionLoading').style.display = 'block';\n  document.getElementById('retentionResults').style.display = 'none';\n  document.getElementById('retentionLoadingMsg').textContent = 'Fetching retention data...';\n\n  try {\n    // Get channel ID from stored data\n    const channelId = window._channelId;\n    if (!channelId) throw new Error('No channel ID \u2014 reconnect YouTube');\n\n    // Fetch retention curve\n    const retRes = await fetch(`/api/retention?access_token=${encodeURIComponent(googleAccessToken)}&video_id=${videoId}&channel_id=${channelId}`);\n    const retData = await retRes.json();\n\n    if (!retData.retention || retData.retention.length < 5) {\n      throw new Error(retData.error || 'No retention data available for this video');\n    }\n\n    document.getElementById('retentionLoadingMsg').textContent = 'Fetching transcript...';\n\n    // Get or fetch transcript\n    let transcript = video.transcript;\n    if (!transcript) {\n      try {\n        const tRes = await fetch(`/api/transcript?videoId=${videoId}`);\n        if (tRes.ok) {\n          const tData = await tRes.json();\n          transcript = typeof tData.content === 'string' ? tData.content :\n            Array.isArray(tData.content) ? tData.content.map(s => s.text).join(' ') : '';\n          video.transcript = transcript;\n        }\n      } catch(e) { transcript = ''; }\n    }\n\n    document.getElementById('retentionLoadingMsg').textContent = 'Diagnosing intro...';\n\n    // Calculate channel avg retention\n    const avgChannelRetention = channelData\n      ? Math.round(channelData.filter(v => !v.isShort && v.avgPctViewed > 0).reduce((s,v) => s + v.avgPctViewed, 0) / channelData.filter(v => !v.isShort && v.avgPctViewed > 0).length)\n      : 35;\n\n    // Run analysis\n    const analysisRes = await fetch('/api/retention-analysis', {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        retention: retData.retention,\n        transcript: transcript || '',\n        title: video.title,\n        views: video.views,\n        avgChannelRetention\n      })\n    });\n\n    const analysisData = await analysisRes.json();\n\n    document.getElementById('retentionLoading').style.display = 'none';\n    renderRetentionResults(retData, analysisData.analysis, transcript, video);\n\n  } catch(err) {\n    document.getElementById('retentionLoading').style.display = 'none';\n    document.getElementById('retentionResults').style.display = 'block';\n    document.getElementById('introVerdict').textContent = 'Error: ' + err.message;\n    document.getElementById('introVerdict').style.color = 'var(--accent2)';\n  }\n}\n\nfunction renderRetentionResults(retData, analysis, transcript, video) {\n  document.getElementById('retentionResults').style.display = 'block';\n\n  // Stats bar\n  const at10 = retData.retention.find(r => r.timePercent >= 10)?.retentionPercent || '\u2014';\n  const at50 = retData.retention.find(r => r.timePercent >= 50)?.retentionPercent || '\u2014';\n  document.getElementById('retentionStats').innerHTML = `\n    <span>Intro drop: <strong style=\"color:${retData.introDrop > 20 ? 'var(--accent2)' : 'var(--green)'}\">${retData.introDrop ? Math.round(retData.introDrop) + '%' : '\u2014'}</strong></span>\n    <span>At 10%: <strong>${at10}%</strong></span>\n    <span>At 50%: <strong>${at50}%</strong></span>\n    <span>Avg: <strong>${retData.avgRetention}%</strong></span>`;\n\n  // Draw retention curve\n  drawRetentionCurve(retData.retention);\n\n  // Intro grade colour\n  const gradeColors = { A: 'var(--green)', B: 'var(--green)', C: 'var(--accent)', D: '#ffb400', F: 'var(--accent2)' };\n  const grade = analysis?.introGrade || '\u2014';\n  document.getElementById('introGrade').textContent = grade;\n  document.getElementById('introGrade').style.color = gradeColors[grade] || 'var(--muted2)';\n\n  // Fill analysis fields\n  document.getElementById('introVerdict').textContent = analysis?.introVerdict || '\u2014';\n  document.getElementById('introDiagnosis').textContent = analysis?.introDiagnosis || '\u2014';\n  document.getElementById('hookPromiseCheck').textContent = analysis?.hookPromiseCheck || '\u2014';\n  document.getElementById('midVideoShape').textContent = analysis?.midVideoShape || '\u2014';\n  document.getElementById('biggestFix').textContent = analysis?.biggestFix || '\u2014';\n  document.getElementById('whatWorked').textContent = analysis?.whatWorked || '\u2014';\n\n  // Show intro script\n  if (transcript) {\n    const words = transcript.split(' ');\n    const introWords = words.slice(0, Math.round(words.length * 0.15)).join(' ');\n    document.getElementById('introScriptText').textContent = introWords + '...';\n  } else {\n    document.getElementById('introScriptText').textContent = 'No transcript available for this video.';\n  }\n}\n\nfunction drawRetentionCurve(retention) {\n  const canvas = document.getElementById('retentionCanvas');\n  const ctx = canvas.getContext('2d');\n  const dpr = window.devicePixelRatio || 1;\n  const rect = canvas.parentElement.getBoundingClientRect();\n\n  canvas.width = rect.width * dpr;\n  canvas.height = 120 * dpr;\n  canvas.style.width = rect.width + 'px';\n  canvas.style.height = '120px';\n  ctx.scale(dpr, dpr);\n\n  const w = rect.width;\n  const h = 120;\n  const pad = { top: 10, bottom: 10, left: 0, right: 0 };\n\n  ctx.clearRect(0, 0, w, h);\n\n  if (!retention.length) return;\n\n  // Draw gradient fill\n  const gradient = ctx.createLinearGradient(0, 0, 0, h);\n  gradient.addColorStop(0, 'rgba(232,255,0,0.15)');\n  gradient.addColorStop(1, 'rgba(232,255,0,0)');\n\n  ctx.beginPath();\n  retention.forEach((point, i) => {\n    const x = pad.left + (point.timePercent / 100) * (w - pad.left - pad.right);\n    const y = pad.top + (1 - point.retentionPercent / 100) * (h - pad.top - pad.bottom);\n    if (i === 0) ctx.moveTo(x, y);\n    else ctx.lineTo(x, y);\n  });\n  // Close path for fill\n  const lastX = pad.left + (retention[retention.length-1].timePercent / 100) * (w - pad.left - pad.right);\n  ctx.lineTo(lastX, h);\n  ctx.lineTo(pad.left, h);\n  ctx.closePath();\n  ctx.fillStyle = gradient;\n  ctx.fill();\n\n  // Draw line\n  ctx.beginPath();\n  ctx.strokeStyle = 'rgba(232,255,0,0.8)';\n  ctx.lineWidth = 2;\n  retention.forEach((point, i) => {\n    const x = pad.left + (point.timePercent / 100) * (w - pad.left - pad.right);\n    const y = pad.top + (1 - point.retentionPercent / 100) * (h - pad.top - pad.bottom);\n    if (i === 0) ctx.moveTo(x, y);\n    else ctx.lineTo(x, y);\n  });\n  ctx.stroke();\n\n  // Mark biggest drop point\n  const biggestDrop = retention.reduce((worst, point, i) => {\n    if (i === 0) return worst;\n    const drop = retention[i-1].retentionPercent - point.retentionPercent;\n    return drop > worst.drop ? { drop, point } : worst;\n  }, { drop: 0, point: null });\n\n  if (biggestDrop.point && biggestDrop.drop > 5) {\n    const x = pad.left + (biggestDrop.point.timePercent / 100) * (w - pad.left - pad.right);\n    const y = pad.top + (1 - biggestDrop.point.retentionPercent / 100) * (h - pad.top - pad.bottom);\n    ctx.beginPath();\n    ctx.arc(x, y, 4, 0, Math.PI * 2);\n    ctx.fillStyle = 'var(--accent2)';\n    ctx.fill();\n  }\n}\n\nfunction showError(msg) {\n  const el = document.getElementById('genError');\n  el.textContent = msg;\n  el.classList.add('show');\n}\n</script>"
